SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A parallel plate capacitor with plate area A and plate separation d is being charged by a constant current I. The displacement current in the region between the plates is:", "explanation": "The displacement current Id = ε₀(dΦE/dt). The electric field between the plates is E = Q/(ε₀A), so the electric flux ΦE = EA = Q/ε₀. Therefore, dΦE/dt = (1/ε₀)(dQ/dt) = I/ε₀. Thus Id = ε₀ × (I/ε₀) = I. The displacement current between the plates is exactly equal to the conduction current I in the connecting wires, ensuring continuity of current in the circuit.", "correct_answer": "D", "concept_tags": ["displacement-current", "capacitor-charging", "current-continuity"], "payload": {"question_id": "cuet-phy-emwave-05", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "I × (d/A)", "is_correct": false}, {"key": "C", "text": "ε₀ × I × A", "is_correct": false}, {"key": "D", "text": "I (equal to the conduction current)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "If displacement current were zero between the plates, Ampere''s circuital law would give different results depending on the chosen surface. Maxwell showed that displacement current bridges this gap.", "misconception": "Thinking no current exists between the capacitor plates"}, {"option_key": "B", "hint": "The displacement current does not depend on the plate separation d. It equals the conduction current regardless of plate geometry, ensuring current continuity.", "misconception": "Incorrectly introducing geometric factors into the displacement current"}, {"option_key": "C", "hint": "ε₀ × I × A has incorrect dimensions (A·m²·s⁴/kg·m³ = not ampere). The displacement current must have units of ampere, and it simply equals I.", "misconception": "Incorrectly multiplying by ε₀ and area"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following electromagnetic waves has the highest frequency?", "explanation": "The electromagnetic spectrum in order of increasing frequency is: radio waves, microwaves, infrared, visible light, ultraviolet, X-rays, gamma rays. Gamma rays have the highest frequency (and shortest wavelength) in the electromagnetic spectrum, typically with frequencies above 3 × 10¹⁹ Hz. They are produced by nuclear reactions and radioactive decay.", "correct_answer": "A", "concept_tags": ["em-spectrum", "frequency-order", "gamma-rays"], "payload": {"question_id": "cuet-phy-emwave-06", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Gamma rays", "is_correct": true}, {"key": "B", "text": "X-rays", "is_correct": false}, {"key": "C", "text": "Ultraviolet rays", "is_correct": false}, {"key": "D", "text": "Microwaves", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "X-rays have very high frequency but gamma rays have even higher frequency. Gamma rays sit at the extreme high-frequency end of the EM spectrum.", "misconception": "Placing X-rays at the highest frequency end of the spectrum"}, {"option_key": "C", "hint": "Ultraviolet rays have higher frequency than visible light but lower frequency than X-rays and gamma rays.", "misconception": "Not knowing the complete ordering of the EM spectrum"}, {"option_key": "D", "hint": "Microwaves have relatively low frequency, between radio waves and infrared. They are far below gamma rays in frequency.", "misconception": "Confusing the position of microwaves in the EM spectrum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the amplitudes of the electric and magnetic fields (E₀/B₀) in an electromagnetic wave travelling in vacuum is equal to:", "explanation": "In an electromagnetic wave in vacuum, the electric and magnetic field amplitudes are related by E₀/B₀ = c = 3 × 10⁸ m/s. This follows from Maxwell''s equations and means that E₀ is much larger in magnitude than B₀ in SI units. At any instant, E = cB for the wave fields. The ratio has dimensions of velocity.", "correct_answer": "B", "concept_tags": ["E-B-ratio", "speed-of-light", "em-wave-properties"], "payload": {"question_id": "cuet-phy-emwave-07", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "c (speed of light in vacuum)", "is_correct": true}, {"key": "C", "text": "1/c", "is_correct": false}, {"key": "D", "text": "c²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "E₀ and B₀ have different units (V/m and T respectively), so their ratio cannot be a dimensionless number like 1. The ratio E₀/B₀ has dimensions of m/s.", "misconception": "Assuming E and B have equal magnitudes in all unit systems"}, {"option_key": "C", "hint": "1/c = B₀/E₀, which is the reciprocal of the correct ratio. If you write B₀ = E₀/c, then E₀/B₀ = c, not 1/c.", "misconception": "Inverting the E-B amplitude relationship"}, {"option_key": "D", "hint": "c² has dimensions of m²/s², whereas E₀/B₀ has dimensions of m/s. The ratio is c, not c².", "misconception": "Confusing the E/B ratio with the expression for c² = 1/(μ₀ε₀)"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following electromagnetic radiations is used in RADAR systems?", "explanation": "RADAR (Radio Detection and Ranging) systems use microwaves because of their short wavelength (compared to radio waves) which allows them to detect smaller objects and provide better angular resolution. Microwaves can penetrate fog, rain, and clouds to some extent, making them ideal for detecting aircraft and ships. Typical RADAR frequencies range from about 1 GHz to 300 GHz.", "correct_answer": "C", "concept_tags": ["microwaves", "radar", "em-wave-applications"], "payload": {"question_id": "cuet-phy-emwave-08", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared radiation", "is_correct": false}, {"key": "B", "text": "Ultraviolet radiation", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared radiation is primarily used for thermal imaging, remote controls, and night vision. It is not used in RADAR systems.", "misconception": "Confusing infrared detection with RADAR detection"}, {"option_key": "B", "hint": "Ultraviolet radiation is absorbed by the atmosphere over long distances and is used in sterilisation, not RADAR.", "misconception": "Not distinguishing between different EM wave applications"}, {"option_key": "D", "hint": "Gamma rays are extremely high-energy radiation from nuclear processes. They are not used in RADAR; they are used in medical imaging (PET scans) and cancer treatment.", "misconception": "Confusing gamma ray applications with RADAR technology"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The energy density (energy per unit volume) in an electromagnetic wave is equally divided between:", "explanation": "In an electromagnetic wave, the energy is equally shared between the electric and magnetic fields. The energy density of the electric field is uE = ½ε₀E² and that of the magnetic field is uB = B²/(2μ₀). Using E = cB and c = 1/√(μ₀ε₀), one can show that uE = uB at every point. The total energy density is u = ε₀E² = B²/μ₀.", "correct_answer": "D", "concept_tags": ["energy-density", "electric-field-energy", "magnetic-field-energy"], "payload": {"question_id": "cuet-phy-emwave-09", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "The kinetic and potential energies", "is_correct": false}, {"key": "B", "text": "The gravitational and electric fields", "is_correct": false}, {"key": "C", "text": "The amplitude and wavelength components", "is_correct": false}, {"key": "D", "text": "The electric and magnetic fields", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Kinetic and potential energy are concepts for mechanical waves and particles. EM waves carry energy in their electric and magnetic fields, not as kinetic/potential energy.", "misconception": "Applying mechanical wave energy concepts to electromagnetic waves"}, {"option_key": "B", "hint": "Gravitational fields are unrelated to electromagnetic wave energy. The energy in EM waves is stored only in the oscillating electric and magnetic fields.", "misconception": "Mixing gravitational and electromagnetic concepts"}, {"option_key": "C", "hint": "Amplitude and wavelength are properties that describe the wave, not energy reservoirs. Energy is stored in the electric and magnetic field components.", "misconception": "Confusing wave parameters with energy storage mechanisms"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A parallel plate capacitor with circular plates of radius R is being charged such that the electric field between the plates changes at the rate dE/dt. The magnetic field at a distance r (r < R) from the axis between the plates is:", "explanation": "Using the Ampere-Maxwell law: ∮B·dl = μ₀ε₀(dΦE/dt) for the region between the plates where there is no conduction current. For a circular Amperian loop of radius r (r < R), the symmetry gives B(2πr) = μ₀ε₀(πr²)(dE/dt). Therefore B = ½μ₀ε₀r(dE/dt). The magnetic field increases linearly with distance from the axis inside the capacitor, similar to the magnetic field inside a current-carrying conductor.", "correct_answer": "D", "concept_tags": ["ampere-maxwell-law", "displacement-current", "magnetic-field-capacitor"], "payload": {"question_id": "cuet-phy-emwave-10", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀ε₀R(dE/dt)/2", "is_correct": false}, {"key": "B", "text": "μ₀ε₀R²(dE/dt)/(2r)", "is_correct": false}, {"key": "C", "text": "μ₀ε₀r²(dE/dt)/(2R)", "is_correct": false}, {"key": "D", "text": "μ₀ε₀r(dE/dt)/2", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This expression uses R instead of r. For r < R, the enclosed flux depends on the area πr², not πR². The magnetic field at distance r depends on r, not R.", "misconception": "Using the full plate radius instead of the Amperian loop radius"}, {"option_key": "B", "hint": "This expression (proportional to R²/r) describes the magnetic field for r > R (outside the plate region), not for r < R. Inside, B is proportional to r.", "misconception": "Applying the formula for the region outside the plates to the inside region"}, {"option_key": "C", "hint": "This has an extra factor of r/R compared to the correct answer. The Amperian loop area πr² divided by 2πr gives r/2, not r²/(2R).", "misconception": "Incorrectly normalizing by the plate radius R"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electromagnetic wave of frequency 10 MHz propagates in vacuum. The wavelength and the magnitude of the magnetic field amplitude, given that the electric field amplitude is 60 V/m, are respectively:", "explanation": "Wavelength λ = c/f = (3 × 10⁸)/(10 × 10⁶) = 30 m. The magnetic field amplitude B₀ = E₀/c = 60/(3 × 10⁸) = 2 × 10⁻⁷ T = 200 nT. This illustrates that for EM waves, the magnetic field amplitude in SI units is much smaller than the electric field amplitude, related by the factor 1/c.", "correct_answer": "B", "concept_tags": ["wavelength-calculation", "E-B-ratio", "frequency-wavelength"], "payload": {"question_id": "cuet-phy-emwave-11", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "30 m and 2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "30 m and 2 × 10⁻⁷ T", "is_correct": true}, {"key": "C", "text": "300 m and 2 × 10⁻⁷ T", "is_correct": false}, {"key": "D", "text": "3 m and 2 × 10⁻⁸ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The wavelength 30 m is correct, but 2 × 10⁻⁶ T is off by a factor of 10. B₀ = 60/(3 × 10⁸) = 2 × 10⁻⁷ T. Check the power of 10 carefully.", "misconception": "Error in power-of-ten calculation for B₀"}, {"option_key": "C", "hint": "300 m would correspond to a frequency of 1 MHz, not 10 MHz. λ = c/f = 3 × 10⁸/10⁷ = 30 m.", "misconception": "Using 10⁶ instead of 10⁷ for the frequency in Hz"}, {"option_key": "D", "hint": "3 m corresponds to f = 100 MHz and 2 × 10⁻⁸ T is also incorrect. Both values are off by a factor of 10 from the correct answer.", "misconception": "Misplacing the decimal in both wavelength and magnetic field calculations"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field of an electromagnetic wave in vacuum is E = 6 sin(10⁷t + kx) ĵ V/m. The value of wave vector k and the direction of propagation are, respectively:", "explanation": "From the wave equation E = E₀sin(ωt + kx), ω = 10⁷ rad/s. Since c = ω/k, we get k = ω/c = 10⁷/(3 × 10⁸) = 1/30 rad/m ≈ 0.033 rad/m. The phase (ωt + kx) with a positive sign for both ω and k indicates the wave propagates in the negative x-direction (−x̂). This is because for a wave travelling in the −x direction, the phase is (ωt + kx), while for +x direction it would be (ωt − kx).", "correct_answer": "C", "concept_tags": ["wave-vector", "propagation-direction", "wave-equation"], "payload": {"question_id": "cuet-phy-emwave-12", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyze", "options": [{"key": "A", "text": "k = 1/30 rad/m, along +x direction", "is_correct": false}, {"key": "B", "text": "k = 30 rad/m, along −x direction", "is_correct": false}, {"key": "C", "text": "k = 1/30 rad/m, along −x direction", "is_correct": true}, {"key": "D", "text": "k = 10⁷ rad/m, along +x direction", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While k = 1/30 rad/m is correct, the +kx term in the phase indicates wave propagation in the −x direction, not +x. The form sin(ωt + kx) travels in the −x̂ direction.", "misconception": "Not recognizing that sin(ωt + kx) represents a wave moving in the −x direction"}, {"option_key": "B", "hint": "k = 30 rad/m is incorrect; k = ω/c = 10⁷/(3 × 10⁸) = 1/30 rad/m. The direction (−x) is correct, though.", "misconception": "Inverting the k = ω/c formula to get k = c/ω"}, {"option_key": "D", "hint": "k = 10⁷ rad/m confuses the angular frequency ω with the wave vector k. Also, the propagation direction is −x, not +x.", "misconception": "Confusing angular frequency ω with wave number k"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electromagnetic waves carry energy and momentum even though they have no mass.\nReason (R): The energy of an electromagnetic wave is shared equally between its oscillating electric and magnetic fields.", "explanation": "Both the assertion and the reason are correct. EM waves carry energy (described by the Poynting vector S = E × B/μ₀) and momentum (p = U/c for energy U) despite being massless. The reason is also true: the average energy density of the electric field (½ε₀E₀²) equals that of the magnetic field (B₀²/(2μ₀)). However, the reason explains only the energy distribution, not why EM waves carry momentum. The momentum arises from the electromagnetic field itself and is related to energy by p = U/c, which is not addressed by the equal energy sharing. Therefore, R is correct but does not fully explain A (specifically the momentum part).", "correct_answer": "B", "concept_tags": ["em-wave-energy", "em-wave-momentum", "energy-density-equipartition"], "payload": {"question_id": "cuet-phy-emwave-13", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the reason only explains energy sharing between E and B fields. It does not explain why massless EM waves carry momentum, which is a key part of the assertion.", "misconception": "Assuming any correct reason that mentions energy automatically explains momentum"}, {"option_key": "C", "hint": "The reason is a correct statement. The energy density of the electric field (½ε₀E²) indeed equals the energy density of the magnetic field (B²/(2μ₀)) in an EM wave.", "misconception": "Thinking energy is not equally distributed between E and B fields"}, {"option_key": "D", "hint": "The assertion is correct: EM waves do carry both energy and momentum despite having no rest mass. This is experimentally verified by radiation pressure.", "misconception": "Thinking massless entities cannot carry momentum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Maxwell modified Ampere''s circuital law by introducing displacement current to make it consistent with the law of conservation of charge.\nReason (R): The conduction current alone was insufficient to explain the magnetic field in the region between the plates of a charging capacitor.", "explanation": "Both A and R are correct, and R is the correct explanation of A. The original Ampere''s law (∮B·dl = μ₀Ic) failed when applied to a surface passing through the gap of a charging capacitor, where no conduction current flows, yet a magnetic field exists. This inconsistency violated the continuity equation (charge conservation). Maxwell resolved this by adding the displacement current term Id = ε₀(dΦE/dt) to Ampere''s law, giving the Ampere-Maxwell law: ∮B·dl = μ₀(Ic + Id). The reason correctly identifies the specific physical situation that necessitated this modification.", "correct_answer": "A", "concept_tags": ["maxwell-modification", "ampere-law", "displacement-current", "charge-conservation"], "payload": {"question_id": "cuet-phy-emwave-14", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion. The charging capacitor scenario in R is exactly the physical situation that exposed the inconsistency in Ampere''s law and motivated Maxwell''s correction described in A.", "misconception": "Not seeing the causal link between the capacitor problem and the modification of Ampere''s law"}, {"option_key": "C", "hint": "The reason is correct: conduction current is indeed zero between capacitor plates during charging, yet a time-varying electric field (and hence a magnetic field) exists there.", "misconception": "Thinking conduction current flows between capacitor plates"}, {"option_key": "D", "hint": "The assertion is correct: Maxwell''s addition of displacement current to Ampere''s law was specifically motivated by ensuring consistency with charge conservation.", "misconception": "Not understanding Maxwell''s historical contribution to electromagnetism"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following types of electromagnetic radiation (Column-I) with their primary applications (Column-II):\n\nColumn-I:\nA. Infrared radiation\nB. X-rays\nC. Ultraviolet radiation\nD. Microwaves\n\nColumn-II:\n1. Cooking in microwave ovens and RADAR\n2. Medical imaging of bones and crystallography\n3. Sterilisation of water and LASIK eye surgery\n4. Night vision devices and TV remote controls", "explanation": "Infrared radiation is used in night vision equipment and TV remote controls (A→4). X-rays penetrate soft tissue but are absorbed by bones, making them ideal for medical imaging; they are also used in crystal structure determination via X-ray diffraction (B→2). Ultraviolet radiation has germicidal properties for water purification and is used in LASIK eye surgery (C→3). Microwaves are used in microwave ovens for heating food and in RADAR systems for detection and ranging (D→1).", "correct_answer": "B", "concept_tags": ["em-spectrum-applications", "infrared", "x-rays", "ultraviolet", "microwaves"], "payload": {"question_id": "cuet-phy-emwave-15", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "B", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-1, B-2, C-4, D-3", "is_correct": false}, {"key": "D", "text": "A-2, B-4, C-1, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps X-rays and UV. X-rays are used for bone imaging (not UV), and UV is used for sterilisation (not X-rays for LASIK).", "misconception": "Confusing the medical applications of X-rays and UV"}, {"option_key": "C", "hint": "This assigns microwave oven use to infrared and remote controls to UV. Infrared is used in remote controls, and microwaves in ovens.", "misconception": "Mixing up infrared and microwave applications"}, {"option_key": "D", "hint": "This assigns bone imaging to infrared, which is incorrect. Infrared cannot penetrate the body to image bones; that requires X-rays.", "misconception": "Thinking infrared radiation can be used for medical bone imaging"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following electromagnetic radiations (Column-I) with their correct source/production mechanism (Column-II):\n\nColumn-I:\nA. Radio waves\nB. X-rays\nC. Gamma rays\nD. Infrared radiation\n\nColumn-II:\n1. Vibrations of atoms and molecules (thermal agitation)\n2. Nuclear transitions and radioactive decay\n3. Oscillating electrons in an LC circuit / antenna\n4. Deceleration of high-speed electrons striking a metal target", "explanation": "Radio waves are produced by oscillating charges in LC circuits connected to antennas (A→3). X-rays are produced when fast-moving electrons are suddenly decelerated upon striking a dense metal target (Bremsstrahlung) or by inner shell electronic transitions (B→4). Gamma rays originate from transitions within the atomic nucleus and radioactive decay processes (C→2). Infrared radiation is emitted by all warm bodies due to thermal vibrations of their atoms and molecules (D→1).", "correct_answer": "C", "concept_tags": ["em-wave-sources", "radio-production", "x-ray-production", "gamma-production", "infrared-production"], "payload": {"question_id": "cuet-phy-emwave-16", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-4, B-3, C-2, D-1", "is_correct": false}, {"key": "C", "text": "A-3, B-4, C-2, D-1", "is_correct": true}, {"key": "D", "text": "A-3, B-4, C-1, D-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps X-ray and gamma ray sources. X-rays come from deceleration of electrons (Bremsstrahlung), not nuclear transitions. Gamma rays come from nuclear processes.", "misconception": "Confusing X-ray and gamma ray production mechanisms"}, {"option_key": "B", "hint": "This assigns electron deceleration to radio waves and LC circuits to X-rays, both of which are incorrect. Radio waves use LC oscillators, and X-rays use electron bombardment.", "misconception": "Reversing the production mechanisms of radio waves and X-rays"}, {"option_key": "D", "hint": "This assigns thermal vibrations to gamma rays and nuclear decay to infrared. Gamma rays are nuclear in origin, and infrared is thermal.", "misconception": "Swapping infrared and gamma ray sources"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "All electromagnetic waves travel with the same speed in vacuum, regardless of their frequency or wavelength.", "explanation": "This statement is TRUE. In vacuum, all electromagnetic waves — from radio waves to gamma rays — travel at the same speed c = 3 × 10⁸ m/s = 1/√(μ₀ε₀). The speed depends only on the properties of free space (μ₀ and ε₀) and is independent of frequency, wavelength, or amplitude. This is a fundamental property that distinguishes vacuum propagation from propagation in a medium, where the speed may vary with frequency (dispersion).", "correct_answer": "A", "concept_tags": ["speed-of-light", "vacuum-propagation", "frequency-independence"], "payload": {"question_id": "cuet-phy-emwave-17", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "In vacuum, there is no dispersion. All EM waves travel at c = 1/√(μ₀ε₀) regardless of frequency. Speed variation with frequency occurs only in material media.", "misconception": "Confusing propagation in a medium (where speed varies with frequency) with propagation in vacuum"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electromagnetic waves are longitudinal waves, similar to sound waves.", "explanation": "This statement is FALSE. Electromagnetic waves are transverse waves, not longitudinal. In EM waves, the electric field E and the magnetic field B oscillate perpendicular to the direction of wave propagation. Sound waves in air are longitudinal (particles oscillate parallel to the propagation direction), but EM waves have a fundamentally different nature. The transverse nature of EM waves is confirmed by the phenomenon of polarisation.", "correct_answer": "B", "concept_tags": ["transverse-wave", "longitudinal-wave", "polarisation"], "payload": {"question_id": "cuet-phy-emwave-18", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "EM waves are transverse, not longitudinal. The E and B vectors oscillate perpendicular to the propagation direction. Polarisation of light is direct evidence of the transverse nature.", "misconception": "Confusing electromagnetic waves with sound waves; both are waves but of fundamentally different types"}, {"option_key": "C", "hint": "This option is not applicable for this question type.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question type.", "misconception": null}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "Maxwell''s modification of Ampere''s circuital law introduces a term called displacement current, given by Id = ε₀(dΦE/dt). In the modified law, the total current enclosed is the sum of _____ current and _____ current.", "explanation": "Maxwell''s modified Ampere''s circuital law is ∮B·dl = μ₀(Ic + Id), where Ic is the conduction current (due to actual flow of charges) and Id = ε₀(dΦE/dt) is the displacement current (due to the time-varying electric field). The conduction current represents the physical movement of charge carriers through conductors, while the displacement current exists even in vacuum or dielectric regions where the electric field is changing with time.", "correct_answer": "A", "concept_tags": ["ampere-maxwell-law", "conduction-current", "displacement-current"], "payload": {"question_id": "cuet-phy-emwave-19", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "conduction; displacement", "is_correct": true}, {"key": "B", "text": "conduction; induction", "is_correct": false}, {"key": "C", "text": "convection; displacement", "is_correct": false}, {"key": "D", "text": "eddy; displacement", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Induction current is the current induced by a changing magnetic flux (Faraday''s law). Maxwell''s addition to Ampere''s law was specifically the displacement current, not induction current.", "misconception": "Confusing displacement current with induced (Faraday) current"}, {"option_key": "C", "hint": "Convection current refers to charge transport by bulk motion of a fluid. The standard form of the Ampere-Maxwell law uses conduction current (flow through conductors), not convection current.", "misconception": "Confusing conduction current with convection current"}, {"option_key": "D", "hint": "Eddy currents are induced circular currents in conductors due to changing magnetic flux. They are not part of the Ampere-Maxwell law formulation.", "misconception": "Confusing eddy currents with the conduction current in Ampere''s law"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A scientist is studying different regions of the electromagnetic spectrum for a research project. She needs to select appropriate EM radiation for the following task: detecting fractures in the internal bone structure of a patient without surgery.\n\nShe also notes that the wavelength of the radiation used should be comparable to interatomic spacing in crystals (about 10⁻¹⁰ m) so that the same radiation can also be used for crystal structure analysis.\n\nThe most suitable electromagnetic radiation for both purposes is:", "explanation": "X-rays are the correct choice for both applications. X-rays have wavelengths in the range of 10⁻⁸ m to 10⁻¹² m, with typical medical X-rays around 10⁻¹⁰ m. They can penetrate soft tissue but are absorbed by dense structures like bones, making them ideal for detecting bone fractures. Additionally, since their wavelength is comparable to interatomic spacings in crystals (~10⁻¹⁰ m or 1 Angstrom), they undergo diffraction when passing through crystalline materials, enabling crystal structure determination (X-ray crystallography). No other region of the EM spectrum satisfies both requirements simultaneously.", "correct_answer": "C", "concept_tags": ["x-rays", "medical-imaging", "crystallography", "em-spectrum-applications"], "payload": {"question_id": "cuet-phy-emwave-20", "subtopic": "Electromagnetic Spectrum and Wave Properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "Ultraviolet radiation", "is_correct": false}, {"key": "B", "text": "Gamma rays", "is_correct": false}, {"key": "C", "text": "X-rays", "is_correct": true}, {"key": "D", "text": "Infrared radiation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "UV radiation has wavelengths of 10⁻⁸ to 4 × 10⁻⁷ m, which is generally too large for crystal diffraction at interatomic spacings. UV also does not penetrate the body sufficiently to image bones.", "misconception": "Thinking UV radiation can penetrate the body to image bones"}, {"option_key": "B", "hint": "While gamma rays can penetrate the body, their wavelengths (< 10⁻¹² m) are much smaller than interatomic spacings, making them less suitable for standard crystal diffraction. They also pose significantly higher radiation hazards.", "misconception": "Thinking gamma rays are routinely used for bone imaging and crystallography"}, {"option_key": "D", "hint": "Infrared radiation has wavelengths of 7 × 10⁻⁷ to 10⁻³ m, far too large for crystal diffraction and unable to penetrate the body to image bones.", "misconception": "Not recognising that infrared cannot penetrate body tissues to reveal bone structure"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic dipole moment of a bar magnet of pole strength m and magnetic length 2l is:", "explanation": "The magnetic dipole moment M of a bar magnet is defined as the product of pole strength (m) and the magnetic length (2l), i.e., M = m × 2l. The direction of M is from the south pole to the north pole inside the magnet.", "correct_answer": "B", "concept_tags": ["magnetic-dipole-moment", "bar-magnet", "pole-strength"], "payload": {"question_id": "cuet-phy-magmat-dipole-01", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "m/2l", "is_correct": false}, {"key": "B", "text": "m × 2l", "is_correct": true}, {"key": "C", "text": "m × l", "is_correct": false}, {"key": "D", "text": "m²× 2l", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Dividing pole strength by length gives units of A (ampere), not A·m². The dipole moment is a product, not a ratio.", "misconception": "Confusing dipole moment formula as a ratio"}, {"option_key": "C", "hint": "The magnetic length of the bar magnet is 2l, not l. Using l would give only half the correct magnetic moment.", "misconception": "Using half-length instead of full magnetic length"}, {"option_key": "D", "hint": "The pole strength appears to the first power in the dipole moment formula, not squared. M = m × 2l, not m² × 2l.", "misconception": "Incorrectly squaring the pole strength"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of magnetic dipole moment is:", "explanation": "Magnetic dipole moment M = NIA (for a current loop) or M = m × 2l (for a bar magnet). Its SI unit is A·m² (ampere-metre squared). This can be verified from M = NIA where current is in amperes and area in m².", "correct_answer": "A", "concept_tags": ["magnetic-moment-unit", "SI-unit", "current-loop"], "payload": {"question_id": "cuet-phy-magmat-dipole-02", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "A·m²", "is_correct": true}, {"key": "B", "text": "A/m²", "is_correct": false}, {"key": "C", "text": "A·m", "is_correct": false}, {"key": "D", "text": "A/m", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A/m² is the SI unit of magnetisation (magnetic moment per unit volume), not the magnetic dipole moment itself.", "misconception": "Confusing magnetic moment with magnetisation"}, {"option_key": "C", "hint": "A·m is the unit of pole strength, not magnetic dipole moment. The moment equals pole strength times length, giving A·m × m = A·m².", "misconception": "Confusing pole strength unit with dipole moment unit"}, {"option_key": "D", "hint": "A/m is the SI unit of magnetic field intensity H, not the magnetic dipole moment.", "misconception": "Confusing with unit of magnetic field intensity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The angle of declination at a place is defined as the angle between:", "explanation": "Declination (or magnetic declination) is the angle between the geographic north (true north) and the magnetic north at a given location on the Earth''s surface. It is one of the three elements of Earth''s magnetism, along with dip and horizontal component.", "correct_answer": "C", "concept_tags": ["declination", "earth-magnetism", "geographic-north", "magnetic-north"], "payload": {"question_id": "cuet-phy-magmat-dipole-03", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "The magnetic meridian and the horizontal plane", "is_correct": false}, {"key": "B", "text": "The geographic meridian and the horizontal plane", "is_correct": false}, {"key": "C", "text": "The geographic meridian and the magnetic meridian", "is_correct": true}, {"key": "D", "text": "The magnetic axis and the rotational axis of Earth", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The angle between the magnetic meridian and the horizontal plane describes the angle of dip (inclination), not declination.", "misconception": "Confusing declination with dip"}, {"option_key": "B", "hint": "The geographic meridian is a vertical plane; its angle with the horizontal is always 90°. Declination is measured in the horizontal plane between two meridians.", "misconception": "Confusing the definition of meridian with horizontal plane"}, {"option_key": "D", "hint": "While the magnetic axis is tilted relative to Earth''s rotational axis (~11.3°), declination is measured locally at each point on the surface between the two meridians.", "misconception": "Confusing global axis tilt with local declination angle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A current loop carrying current I and having area A behaves as a magnetic dipole with moment:", "explanation": "A planar current loop of N turns, each carrying current I and enclosing area A, acts as a magnetic dipole with magnetic moment M = NIA. For a single turn (N = 1), M = IA. The direction of M is given by the right-hand rule: curl the fingers in the direction of current, and the thumb points along M.", "correct_answer": "D", "concept_tags": ["current-loop", "magnetic-dipole", "magnetic-moment"], "payload": {"question_id": "cuet-phy-magmat-dipole-04", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "M = I/A", "is_correct": false}, {"key": "B", "text": "M = I²A", "is_correct": false}, {"key": "C", "text": "M = IA²", "is_correct": false}, {"key": "D", "text": "M = IA", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Dividing current by area gives A/m², which is the unit of current density, not magnetic moment. The moment is the product I × A.", "misconception": "Confusing dipole moment with current density"}, {"option_key": "B", "hint": "The current appears to the first power in M = IA. Squaring the current has no physical basis in the magnetic moment formula.", "misconception": "Incorrectly squaring the current"}, {"option_key": "C", "hint": "The area appears to the first power. IA² would have units of A·m⁴, which is not the unit of magnetic moment (A·m²).", "misconception": "Incorrectly squaring the area"}]}}]'::jsonb, 'deploy-2026-03-05-b12');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field on the axial line of a short bar magnet at a distance r from its centre is B₁, and the field on the equatorial line at the same distance is B₂. The ratio B₁/B₂ is:", "explanation": "For a short bar magnet (magnetic dipole), the axial field is B_axial = (μ₀/4π)(2M/r³) and the equatorial field is B_equatorial = (μ₀/4π)(M/r³). Therefore, B₁/B₂ = 2M/r³ ÷ M/r³ = 2. The axial field is always twice the equatorial field at the same distance.", "correct_answer": "C", "concept_tags": ["axial-field", "equatorial-field", "bar-magnet", "field-ratio"], "payload": {"question_id": "cuet-phy-magmat-dipole-05", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "1/2", "is_correct": false}, {"key": "C", "text": "2", "is_correct": true}, {"key": "D", "text": "4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A ratio of 1 would mean the axial and equatorial fields are equal, but the axial field formula has an extra factor of 2 compared to the equatorial field.", "misconception": "Thinking axial and equatorial fields are equal"}, {"option_key": "B", "hint": "A ratio of 1/2 would mean the axial field is weaker than the equatorial field. In fact, the axial field is stronger (has the factor 2).", "misconception": "Inverting the axial-to-equatorial ratio"}, {"option_key": "D", "hint": "A ratio of 4 would require the axial field to have a factor of 4M instead of 2M. The correct axial field is (μ₀/4π)(2M/r³).", "misconception": "Squaring the factor of 2"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A short bar magnet of magnetic moment 0.4 J/T is placed in a uniform magnetic field of 0.16 T. The torque on the magnet when it makes an angle of 30° with the field is:", "explanation": "Torque τ = MB sinθ = 0.4 × 0.16 × sin30° = 0.4 × 0.16 × 0.5 = 0.032 N·m. The torque acts to align the magnetic moment with the external field direction.", "correct_answer": "B", "concept_tags": ["torque-on-dipole", "magnetic-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmat-dipole-06", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "0.064 N·m", "is_correct": false}, {"key": "B", "text": "0.032 N·m", "is_correct": true}, {"key": "C", "text": "0.016 N·m", "is_correct": false}, {"key": "D", "text": "0.08 N·m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.064 = 0.4 × 0.16, which omits the sin30° = 0.5 factor. The torque formula is MB sinθ, not just MB.", "misconception": "Forgetting to multiply by sinθ"}, {"option_key": "C", "hint": "0.016 would result from an extra factor of 1/2, perhaps from using sin30° twice. The correct calculation is 0.4 × 0.16 × 0.5 = 0.032.", "misconception": "Applying an extra factor of 1/2"}, {"option_key": "D", "hint": "0.08 = 0.4 × 0.2. Check the field value: it is 0.16 T, not 0.2 T.", "misconception": "Misreading the given field value"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "At a place, the horizontal component of Earth''s magnetic field is Bₕ = 0.3 G and the angle of dip is 60°. The total magnetic field of the Earth at that place is:", "explanation": "The relation between horizontal component and total field is Bₕ = B cosδ, where δ is the angle of dip. Therefore B = Bₕ/cosδ = 0.3/cos60° = 0.3/0.5 = 0.6 G. The total field B has both horizontal (Bₕ) and vertical (Bᵥ) components.", "correct_answer": "D", "concept_tags": ["earth-magnetic-field", "dip-angle", "horizontal-component", "numerical"], "payload": {"question_id": "cuet-phy-magmat-dipole-07", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "0.15 G", "is_correct": false}, {"key": "B", "text": "0.3 G", "is_correct": false}, {"key": "C", "text": "0.45 G", "is_correct": false}, {"key": "D", "text": "0.6 G", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.15 G = Bₕ × cos60°, which would give Bₕ × cosδ = a component, not the total field. You need to divide by cosδ, not multiply.", "misconception": "Multiplying by cosδ instead of dividing"}, {"option_key": "B", "hint": "0.3 G is the horizontal component itself, not the total field. The total field is always greater than or equal to the horizontal component.", "misconception": "Confusing horizontal component with total field"}, {"option_key": "C", "hint": "0.45 G = 0.3 × 1.5, which doesn''t follow from any correct formula. Use B = Bₕ/cos60° = 0.3/0.5 = 0.6 G.", "misconception": "Arithmetic error in the division"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A bar magnet of magnetic moment M is cut into two equal halves along its length. The magnetic moment of each half is:", "explanation": "When a bar magnet is cut into two equal halves along its length (longitudinally), the pole strength of each half becomes m/2 (since the cross-section is halved), but the magnetic length remains 2l. Therefore, the magnetic moment of each half = (m/2) × 2l = M/2.", "correct_answer": "A", "concept_tags": ["bar-magnet-cutting", "magnetic-moment", "pole-strength"], "payload": {"question_id": "cuet-phy-magmat-dipole-08", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "M/2", "is_correct": true}, {"key": "B", "text": "M", "is_correct": false}, {"key": "C", "text": "2M", "is_correct": false}, {"key": "D", "text": "M/4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The moment cannot remain M because the pole strength is halved when the cross-section is divided. M = (m/2) × 2l = M/2.", "misconception": "Thinking that cutting along length does not change the moment"}, {"option_key": "C", "hint": "Cutting a magnet cannot increase its magnetic moment. The total moment of all pieces cannot exceed the original moment.", "misconception": "Incorrectly doubling the moment"}, {"option_key": "D", "hint": "M/4 would result if both pole strength and length were halved, but longitudinal cutting only halves the pole strength, not the length.", "misconception": "Confusing longitudinal cutting with a combination of longitudinal and transverse cuts"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The potential energy of a magnetic dipole in a uniform magnetic field B is minimum when the angle between M and B is:", "explanation": "The potential energy of a magnetic dipole is U = −M·B = −MB cosθ. This is minimum when cosθ is maximum, i.e., cosθ = 1, which gives θ = 0°. At this position, the dipole is aligned with the field and is in stable equilibrium.", "correct_answer": "A", "concept_tags": ["potential-energy", "stable-equilibrium", "magnetic-dipole"], "payload": {"question_id": "cuet-phy-magmat-dipole-09", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "0°", "is_correct": true}, {"key": "B", "text": "90°", "is_correct": false}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "45°", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "At θ = 90°, U = −MB cos90° = 0, which is neither the minimum nor the maximum value of potential energy.", "misconception": "Confusing zero energy with minimum energy"}, {"option_key": "C", "hint": "At θ = 180°, U = −MB cos180° = +MB, which is the maximum potential energy (unstable equilibrium), not the minimum.", "misconception": "Confusing unstable equilibrium with stable equilibrium"}, {"option_key": "D", "hint": "At θ = 45°, U = −MB cos45° = −MB/√2, which is less than zero but not the minimum. The minimum occurs at θ = 0° where U = −MB.", "misconception": "Choosing an arbitrary intermediate angle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at a point on the axial line of a short bar magnet at a distance of 20 cm is 4 × 10⁻⁶ T. The magnetic field at a point on the equatorial line at the same distance is:", "explanation": "For a short bar magnet, B_axial = (μ₀/4π)(2M/r³) and B_equatorial = (μ₀/4π)(M/r³). Therefore B_equatorial = B_axial/2 = 4 × 10⁻⁶/2 = 2 × 10⁻⁶ T. The equatorial field is always half the axial field at the same distance from the centre.", "correct_answer": "B", "concept_tags": ["axial-equatorial-field", "numerical", "bar-magnet-field"], "payload": {"question_id": "cuet-phy-magmat-dipole-10", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "4 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁶ T", "is_correct": true}, {"key": "C", "text": "8 × 10⁻⁶ T", "is_correct": false}, {"key": "D", "text": "1 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assumes the axial and equatorial fields are equal. The equatorial field is half the axial field at the same distance.", "misconception": "Thinking axial and equatorial fields are equal"}, {"option_key": "C", "hint": "8 × 10⁻⁶ T = 2 × B_axial. The equatorial field is smaller than the axial field, not larger.", "misconception": "Inverting the relationship and doubling instead of halving"}, {"option_key": "D", "hint": "1 × 10⁻⁶ T = B_axial/4. The correct ratio is B_eq = B_axial/2, not B_axial/4.", "misconception": "Using an incorrect division factor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A short bar magnet has a magnetic moment of 0.48 J/T. The magnetic field at a point on the axial line at a distance of 10 cm from the centre of the magnet is: (Given: μ₀/4π = 10⁻⁷ T·m/A)", "explanation": "B_axial = (μ₀/4π)(2M/r³) = 10⁻⁷ × 2 × 0.48 / (0.1)³ = 10⁻⁷ × 0.96 / 10⁻³ = 10⁻⁷ × 960 = 9.6 × 10⁻⁵ T. Converting: 9.6 × 10⁻⁵ T = 0.96 × 10⁻⁴ T.", "correct_answer": "C", "concept_tags": ["axial-field", "numerical-problem", "bar-magnet-field-calculation"], "payload": {"question_id": "cuet-phy-magmat-dipole-11", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "4.8 × 10⁻⁵ T", "is_correct": false}, {"key": "B", "text": "2.4 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "9.6 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "19.2 × 10⁻⁵ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4.8 × 10⁻⁵ T uses M/r³ instead of 2M/r³. The axial field formula has a factor of 2: B = (μ₀/4π)(2M/r³).", "misconception": "Forgetting the factor of 2 in the axial field formula"}, {"option_key": "B", "hint": "2.4 × 10⁻⁵ T = (μ₀/4π)(M/2r³). This uses neither the correct axial formula nor the equatorial formula.", "misconception": "Using an incorrect formula"}, {"option_key": "D", "hint": "19.2 × 10⁻⁵ T = 2 × 9.6 × 10⁻⁵ T. This doubles the correct answer, suggesting an error in handling powers of ten or an extra factor of 2.", "misconception": "Arithmetic error in powers of 10"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The work done in turning a magnetic needle from the direction of the horizontal component Bₕ of Earth''s field to a direction making an angle of 60° with Bₕ is W. The torque required to hold the needle in that position is:", "explanation": "Work done: W = MBₕ(1 − cos60°) = MBₕ(1 − 1/2) = MBₕ/2. Therefore MBₕ = 2W. The torque at 60° is τ = MBₕ sin60° = 2W × (√3/2) = √3 W. Hence τ = √3 W.", "correct_answer": "D", "concept_tags": ["torque", "work-done", "earth-field", "numerical-reasoning"], "payload": {"question_id": "cuet-phy-magmat-dipole-12", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "analyze", "options": [{"key": "A", "text": "W", "is_correct": false}, {"key": "B", "text": "2W", "is_correct": false}, {"key": "C", "text": "W/2", "is_correct": false}, {"key": "D", "text": "√3 W", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This assumes τ = W, but the torque and work done have different angular dependencies (sinθ vs 1−cosθ). You must express MBₕ from the work equation and substitute into the torque formula.", "misconception": "Equating torque directly with work done"}, {"option_key": "B", "hint": "2W = MBₕ is the product of moment and field, not the torque. The torque has an additional sin60° = √3/2 factor.", "misconception": "Confusing MBₕ with torque"}, {"option_key": "C", "hint": "W/2 would result from an incorrect formula. From MBₕ = 2W, the torque is MBₕ sin60° = 2W × √3/2 = √3 W.", "misconception": "Arithmetic error in combining the expressions"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A bar magnet is equivalent to a solenoid carrying current.\nReason (R): The magnetic field lines of a bar magnet and a current-carrying solenoid have identical patterns, with field lines emerging from one end and entering the other.", "explanation": "The assertion is correct: a bar magnet behaves identically to a solenoid in terms of its external magnetic field. The reason is also correct and directly explains the assertion: both produce the same field pattern — field lines emerge from the north pole (or the end where current flows anticlockwise) and enter the south pole (or the end where current flows clockwise). The mathematical expressions for the fields at axial and equatorial points are also identical when M = NIA.", "correct_answer": "A", "concept_tags": ["bar-magnet-solenoid-equivalence", "magnetic-field-pattern", "current-loop"], "payload": {"question_id": "cuet-phy-magmat-dipole-13", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The identical field line pattern is exactly what establishes the equivalence of a bar magnet and a solenoid, so R is indeed the correct explanation of A.", "misconception": "Failing to see that identical field patterns establish the equivalence"}, {"option_key": "C", "hint": "The reason is a correct statement. Both bar magnets and solenoids produce the same dipolar field pattern outside.", "misconception": "Doubting the field pattern similarity"}, {"option_key": "D", "hint": "The assertion is well-established in physics. A bar magnet is indeed equivalent to a solenoid, and this is a standard result in magnetism.", "misconception": "Not recognizing the bar-magnet-solenoid equivalence"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): At the magnetic equator, the angle of dip is 0° and a freely suspended magnetic needle rests horizontally.\nReason (R): At the magnetic equator, the vertical component of Earth''s magnetic field is zero.", "explanation": "The assertion is correct: at the magnetic equator, the dip angle δ = 0°, and a freely suspended needle aligns horizontally. The reason is also correct and directly explains the assertion: since Bᵥ = B sinδ, at δ = 0° we get Bᵥ = 0. With no vertical component to pull the needle downward, it rests horizontally. The entire Earth''s field at the magnetic equator is horizontal (Bₕ = B).", "correct_answer": "A", "concept_tags": ["magnetic-equator", "dip-angle", "vertical-component", "horizontal-component"], "payload": {"question_id": "cuet-phy-magmat-dipole-14", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains the assertion: the needle rests horizontally precisely because the vertical component is zero. The causal connection is clear.", "misconception": "Not connecting zero vertical component with the horizontal resting position"}, {"option_key": "C", "hint": "The reason is correct. At δ = 0°, Bᵥ = B sin0° = 0. This is a direct consequence of the dip angle being zero.", "misconception": "Incorrectly thinking the vertical component is non-zero at the magnetic equator"}, {"option_key": "D", "hint": "The assertion is correct and verifiable. At the magnetic equator, dip is indeed 0° and the needle does rest horizontally.", "misconception": "Confusing magnetic equator with geographic equator and doubting the assertion"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the elements of Earth''s magnetism in Column I with their definitions in Column II:\n\nColumn I:\nA. Declination\nB. Angle of dip (Inclination)\nC. Horizontal component Bₕ\nD. Vertical component Bᵥ\n\nColumn II:\n1. B sinδ, where δ is the dip angle\n2. The angle between the geographic meridian and the magnetic meridian\n3. B cosδ, where δ is the dip angle\n4. The angle between the total Earth''s field and the horizontal direction in the magnetic meridian", "explanation": "Declination is the angle between geographic and magnetic meridians → A-2. Dip is the angle between the total field vector and the horizontal in the magnetic meridian → B-4. The horizontal component is Bₕ = B cosδ → C-3. The vertical component is Bᵥ = B sinδ → D-1.", "correct_answer": "C", "concept_tags": ["earth-magnetism-elements", "declination", "dip", "horizontal-vertical-components"], "payload": {"question_id": "cuet-phy-magmat-dipole-15", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "understand", "options": [{"key": "A", "text": "A-4, B-2, C-3, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-1, D-3", "is_correct": false}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": true}, {"key": "D", "text": "A-2, B-3, C-4, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps A and B. Declination is the angle between meridians (definition 2), while dip is the angle of the total field with horizontal (definition 4).", "misconception": "Confusing declination with dip"}, {"option_key": "B", "hint": "This swaps C and D. The horizontal component uses cosδ (C-3), and the vertical component uses sinδ (D-1), not the other way around.", "misconception": "Interchanging sinδ and cosδ for horizontal and vertical components"}, {"option_key": "D", "hint": "This assigns definition 3 (B cosδ) to dip, but dip is an angle (definition 4), not a field component.", "misconception": "Confusing the dip angle with a field component formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situations in Column I with the correct magnetic field expressions or properties in Column II:\n\nColumn I:\nA. Axial point of a magnetic dipole (far field)\nB. Equatorial point of a magnetic dipole (far field)\nC. Neutral point when N-pole points north (bar magnet on table)\nD. Neutral point when N-pole points south (bar magnet on table)\n\nColumn II:\n1. Located on the axial line of the magnet\n2. (μ₀/4π)(M/r³), directed opposite to M\n3. Located on the equatorial line of the magnet\n4. (μ₀/4π)(2M/r³), directed along M", "explanation": "The axial field at far distance is (μ₀/4π)(2M/r³), directed along M → A-4. The equatorial field at far distance is (μ₀/4π)(M/r³), directed opposite to M → B-2. When the N-pole of a bar magnet points geographic north, the magnet''s field opposes Earth''s field on the equatorial line, so neutral points are on the equatorial line → C-3. When the N-pole points south, neutral points lie on the axial line → D-1.", "correct_answer": "B", "concept_tags": ["axial-equatorial-field", "neutral-points", "bar-magnet-earth-field"], "payload": {"question_id": "cuet-phy-magmat-dipole-16", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "analyze", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-2, C-3, D-1", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-2, C-1, D-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps C and D. When N-pole points north, the axial field adds to Earth''s field and the equatorial field opposes it, so neutral points are on the equatorial line (C-3, not C-1).", "misconception": "Confusing which line has neutral points for N-pole pointing north vs south"}, {"option_key": "C", "hint": "This swaps A and B. The axial field has the factor 2 in the numerator and is along M; the equatorial field has factor 1 and is opposite to M.", "misconception": "Interchanging axial and equatorial field formulas"}, {"option_key": "D", "hint": "This is identical to option A with C and D swapped from the correct answer. Neutral points for N-pole north are on the equatorial line (perpendicular bisector), not the axial line.", "misconception": "Confusing the location of neutral points"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field lines of a bar magnet form continuous closed loops, emerging from the north pole outside the magnet and running from south to north inside the magnet.", "explanation": "This statement is TRUE. Unlike electric field lines, magnetic field lines always form continuous closed loops. Outside the magnet, they go from north pole to south pole. Inside the magnet, they continue from south pole to north pole, completing the loop. This is a consequence of Gauss''s law for magnetism (∇·B = 0), which states that magnetic monopoles do not exist.", "correct_answer": "A", "concept_tags": ["magnetic-field-lines", "closed-loops", "gauss-law-magnetism"], "payload": {"question_id": "cuet-phy-magmat-dipole-17", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Magnetic field lines do form closed loops. This is a fundamental difference between electric field lines (which start and end on charges) and magnetic field lines (which have no starting or ending points because magnetic monopoles don''t exist).", "misconception": "Confusing magnetic field lines with electric field lines that do not form closed loops"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The geographic north pole of the Earth and the magnetic north pole of the Earth are located at the same point.", "explanation": "This statement is FALSE. The geographic north pole (true north, defined by Earth''s rotational axis) and the magnetic north pole (where the Earth''s magnetic field points vertically downward) are NOT at the same location. The magnetic north pole is offset from the geographic north pole by about 11.3°. In fact, the Earth''s magnetic south pole is located near the geographic north pole (since field lines enter the Earth near the geographic north).", "correct_answer": "B", "concept_tags": ["geographic-pole", "magnetic-pole", "earth-magnetism"], "payload": {"question_id": "cuet-phy-magmat-dipole-18", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The geographic and magnetic poles do not coincide. The angle between the geographic meridian and magnetic meridian (declination) varies across the globe, precisely because these poles are at different locations.", "misconception": "Assuming geographic and magnetic north poles are at the same location"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "At a place where the angle of dip is 45°, the horizontal and vertical components of Earth''s magnetic field are _____.", "explanation": "When the angle of dip δ = 45°, we have Bₕ = B cos45° = B/√2 and Bᵥ = B sin45° = B/√2. Since Bₕ = Bᵥ, the horizontal and vertical components are equal in magnitude. Also, tanδ = Bᵥ/Bₕ = tan45° = 1, confirming Bᵥ = Bₕ.", "correct_answer": "C", "concept_tags": ["dip-angle", "horizontal-component", "vertical-component", "equal-components"], "payload": {"question_id": "cuet-phy-magmat-dipole-19", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "Bₕ = 2Bᵥ (horizontal is twice the vertical)", "is_correct": false}, {"key": "B", "text": "Bᵥ = 2Bₕ (vertical is twice the horizontal)", "is_correct": false}, {"key": "C", "text": "Equal in magnitude (Bₕ = Bᵥ)", "is_correct": true}, {"key": "D", "text": "Bₕ = 0 and Bᵥ = B (only vertical component exists)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Bₕ = 2Bᵥ would require tanδ = 1/2, giving δ ≈ 26.6°, not 45°. At δ = 45°, tanδ = 1, so Bₕ = Bᵥ.", "misconception": "Incorrect trigonometric evaluation at 45°"}, {"option_key": "B", "hint": "Bᵥ = 2Bₕ would require tanδ = 2, giving δ ≈ 63.4°. At 45° dip, both components are equal.", "misconception": "Confusing 45° dip with a steeper dip angle"}, {"option_key": "D", "hint": "Bₕ = 0 occurs only at the magnetic poles where δ = 90°. At δ = 45°, both horizontal and vertical components are non-zero and equal.", "misconception": "Confusing 45° dip with 90° dip (at the poles)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-dipole", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A geologist is surveying a region using a dip circle. At a particular location, she measures the angle of dip to be 30° and the horizontal component of Earth''s magnetic field to be 0.36 G. She needs to determine the total magnetic field strength and the vertical component at this location.\n\nWhat is the vertical component Bᵥ of Earth''s magnetic field at this location?", "explanation": "Given: δ = 30°, Bₕ = 0.36 G. Using the relation tanδ = Bᵥ/Bₕ, we get Bᵥ = Bₕ tanδ = 0.36 × tan30° = 0.36 × (1/√3) = 0.36/1.732 ≈ 0.208 G. Alternatively, Bᵥ = 0.36/√3 = 0.12√3 G ≈ 0.208 G. The total field B = Bₕ/cosδ = 0.36/cos30° = 0.36/(√3/2) = 0.72/√3 ≈ 0.416 G.", "correct_answer": "D", "concept_tags": ["earth-magnetism", "dip-angle", "vertical-component", "scenario-based", "numerical"], "payload": {"question_id": "cuet-phy-magmat-dipole-20", "subtopic": "Magnetic Dipole and Torque", "topic_name": "Magnetic Dipole and Torque", "bloom_level": "apply", "options": [{"key": "A", "text": "0.36 G", "is_correct": false}, {"key": "B", "text": "0.72 G", "is_correct": false}, {"key": "C", "text": "0.18 G", "is_correct": false}, {"key": "D", "text": "0.12√3 G ≈ 0.208 G", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "0.36 G is the horizontal component, not the vertical component. With a dip of 30°, the vertical component is smaller than the horizontal component since tan30° < 1.", "misconception": "Confusing horizontal component with vertical component"}, {"option_key": "B", "hint": "0.72 G = 2 × Bₕ. This might result from using an incorrect formula. The correct relation is Bᵥ = Bₕ tan30° = 0.36 × (1/√3) ≈ 0.208 G.", "misconception": "Using an incorrect multiplying factor"}, {"option_key": "C", "hint": "0.18 G = Bₕ/2 = Bₕ × sin30°, but the correct formula is Bᵥ = Bₕ tanδ, not Bₕ sinδ.", "misconception": "Using sinδ instead of tanδ in the formula for Bᵥ"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is a diamagnetic substance?", "explanation": "Bismuth (Bi) is a classic diamagnetic substance. Diamagnetic materials have all electrons paired, leading to a small negative susceptibility (χ < 0). They are weakly repelled by a magnetic field. Aluminium is paramagnetic, iron and cobalt are ferromagnetic.", "correct_answer": "C", "concept_tags": ["diamagnetic-materials", "examples", "magnetic-classification"], "payload": {"question_id": "cuet-phy-magmat-materials-01", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Aluminium", "is_correct": false}, {"key": "B", "text": "Iron", "is_correct": false}, {"key": "C", "text": "Bismuth", "is_correct": true}, {"key": "D", "text": "Cobalt", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Aluminium has unpaired electrons and is weakly attracted by a magnetic field. It is paramagnetic, not diamagnetic.", "misconception": "Confusing paramagnetic metals with diamagnetic ones"}, {"option_key": "B", "hint": "Iron is the most well-known ferromagnetic material. It is strongly attracted by magnets and can be permanently magnetised.", "misconception": "Confusing ferromagnetic with diamagnetic"}, {"option_key": "D", "hint": "Cobalt is ferromagnetic like iron and nickel. It has a high Curie temperature (~1115°C) and is strongly magnetic.", "misconception": "Not knowing the classification of common magnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic susceptibility (χ) of a paramagnetic material is:", "explanation": "Paramagnetic materials have a small positive magnetic susceptibility (0 < χ << 1). They are weakly attracted by an external magnetic field. The atomic magnetic dipoles tend to align along the field but thermal agitation prevents complete alignment, keeping χ small and positive.", "correct_answer": "B", "concept_tags": ["magnetic-susceptibility", "paramagnetic", "chi-positive"], "payload": {"question_id": "cuet-phy-magmat-materials-02", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Large and negative", "is_correct": false}, {"key": "B", "text": "Small and positive", "is_correct": true}, {"key": "C", "text": "Large and positive", "is_correct": false}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Negative susceptibility is the hallmark of diamagnetic materials, not paramagnetic. Also, diamagnetic susceptibility is small in magnitude, not large.", "misconception": "Confusing diamagnetic susceptibility sign with paramagnetic"}, {"option_key": "C", "hint": "Large and positive susceptibility (~10³ to 10⁵) is characteristic of ferromagnetic materials, not paramagnetic. Paramagnetic χ is of the order of 10⁻⁵ to 10⁻³.", "misconception": "Confusing ferromagnetic susceptibility with paramagnetic"}, {"option_key": "D", "hint": "Zero susceptibility would mean the material is completely non-magnetic, which is not the case. Even diamagnetic materials have non-zero (negative) susceptibility.", "misconception": "Thinking paramagnetic materials have no magnetic response"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Curie''s law states that the magnetic susceptibility of a paramagnetic substance is:", "explanation": "According to Curie''s law, the magnetic susceptibility (χ) of a paramagnetic material is inversely proportional to its absolute temperature: χ = C/T, where C is the Curie constant. As temperature increases, thermal agitation disrupts the alignment of magnetic dipoles, reducing susceptibility.", "correct_answer": "A", "concept_tags": ["curie-law", "paramagnetic", "temperature-dependence", "susceptibility"], "payload": {"question_id": "cuet-phy-magmat-materials-03", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Inversely proportional to absolute temperature", "is_correct": true}, {"key": "B", "text": "Directly proportional to absolute temperature", "is_correct": false}, {"key": "C", "text": "Inversely proportional to the square of absolute temperature", "is_correct": false}, {"key": "D", "text": "Independent of temperature", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If susceptibility increased with temperature, paramagnetic materials would become more magnetic when heated. In reality, heating disrupts dipole alignment and reduces χ.", "misconception": "Reversing the relationship between χ and T in Curie''s law"}, {"option_key": "C", "hint": "Curie''s law gives χ ∝ 1/T, not 1/T². The inverse-square dependence does not apply here.", "misconception": "Confusing with other inverse-square laws in physics"}, {"option_key": "D", "hint": "Diamagnetic susceptibility is approximately independent of temperature, but paramagnetic susceptibility varies as 1/T according to Curie''s law.", "misconception": "Confusing temperature dependence of diamagnetic and paramagnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The relative magnetic permeability (μᵣ) of a ferromagnetic material is:", "explanation": "Ferromagnetic materials have very high relative permeability, typically μᵣ >> 1 (can range from 10² to 10⁵). This means they greatly enhance the magnetic field inside them. The relation μᵣ = 1 + χ shows that since χ >> 1 for ferromagnets, μᵣ >> 1.", "correct_answer": "D", "concept_tags": ["relative-permeability", "ferromagnetic", "mu-r"], "payload": {"question_id": "cuet-phy-magmat-materials-04", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Slightly less than 1", "is_correct": false}, {"key": "B", "text": "Equal to zero", "is_correct": false}, {"key": "C", "text": "Slightly greater than 1", "is_correct": false}, {"key": "D", "text": "Much greater than 1", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Slightly less than 1 (μᵣ < 1) is the characteristic of diamagnetic materials where χ is small and negative.", "misconception": "Confusing diamagnetic permeability with ferromagnetic"}, {"option_key": "B", "hint": "Zero permeability would mean no magnetic field can exist inside the material. No real material has μᵣ = 0.", "misconception": "Fundamental misunderstanding of permeability"}, {"option_key": "C", "hint": "Slightly greater than 1 (μᵣ ≈ 1 + small positive χ) is characteristic of paramagnetic materials, not ferromagnetic ones.", "misconception": "Confusing paramagnetic permeability with ferromagnetic"}]}}]'::jsonb, 'deploy-2026-03-05-b12');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Above the Curie temperature, a ferromagnetic material behaves as a:", "explanation": "Above the Curie temperature (Tc), the thermal energy overcomes the exchange interaction that aligns neighbouring atomic dipoles in domains. The spontaneous magnetisation is destroyed and the material loses its ferromagnetic properties, behaving as a paramagnetic substance. The susceptibility then follows the Curie–Weiss law: χ = C/(T − Tc).", "correct_answer": "B", "concept_tags": ["curie-temperature", "ferromagnetic-transition", "paramagnetic"], "payload": {"question_id": "cuet-phy-magmat-materials-05", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "Diamagnetic material", "is_correct": false}, {"key": "B", "text": "Paramagnetic material", "is_correct": true}, {"key": "C", "text": "Superconductor", "is_correct": false}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic behaviour arises from paired electrons and is an intrinsic atomic property. A ferromagnet above Tc still has unpaired electrons and atomic moments; only the cooperative alignment is lost.", "misconception": "Thinking loss of ferromagnetism means diamagnetism"}, {"option_key": "C", "hint": "Superconductors exhibit perfect diamagnetism (Meissner effect) and require very low temperatures. Heating above Tc does not produce superconductivity.", "misconception": "Confusing Curie temperature transition with superconducting transition"}, {"option_key": "D", "hint": "A permanent magnet requires domain alignment which is destroyed by heating above Tc. The material cannot retain magnetisation above its Curie temperature.", "misconception": "Thinking heating strengthens magnetic properties"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a hysteresis loop of a ferromagnetic material, the retentivity represents:", "explanation": "Retentivity (or remanence) is the magnetisation (or magnetic flux density B) retained by the ferromagnetic material after the magnetising field H is reduced to zero. On the B-H curve, it is the value of B when H = 0 on the descending branch of the loop.", "correct_answer": "A", "concept_tags": ["hysteresis", "retentivity", "remanence", "B-H-curve"], "payload": {"question_id": "cuet-phy-magmat-materials-06", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic flux density remaining when the magnetising field is reduced to zero", "is_correct": true}, {"key": "B", "text": "The magnetising field needed to reduce the magnetic flux density to zero", "is_correct": false}, {"key": "C", "text": "The maximum magnetic flux density achieved during magnetisation", "is_correct": false}, {"key": "D", "text": "The energy lost per cycle of magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The magnetising field required to reduce B to zero is called coercivity, not retentivity. These are two distinct quantities on the hysteresis loop.", "misconception": "Confusing retentivity with coercivity"}, {"option_key": "C", "hint": "The maximum B achieved is the saturation magnetisation, which occurs at high H values. Retentivity is what remains after H is removed.", "misconception": "Confusing saturation magnetisation with retentivity"}, {"option_key": "D", "hint": "The energy dissipated per cycle equals the area enclosed by the hysteresis loop. This is hysteresis loss, not retentivity.", "misconception": "Confusing hysteresis loss with retentivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "For making permanent magnets, materials with which of the following properties are preferred?", "explanation": "Permanent magnets must retain strong magnetisation. This requires high retentivity (to maintain a large residual field) and high coercivity (so the magnetisation is not easily destroyed by stray fields or mechanical vibrations). Steel, Alnico, and Nd₂Fe₁₄B are examples of such hard magnetic materials.", "correct_answer": "C", "concept_tags": ["permanent-magnets", "retentivity", "coercivity", "hard-magnetic"], "payload": {"question_id": "cuet-phy-magmat-materials-07", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "High retentivity and low coercivity", "is_correct": false}, {"key": "B", "text": "Low retentivity and high coercivity", "is_correct": false}, {"key": "C", "text": "High retentivity and high coercivity", "is_correct": true}, {"key": "D", "text": "Low retentivity and low coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Low coercivity means the magnet can be easily demagnetised by small external fields. A permanent magnet must resist demagnetisation, requiring high coercivity.", "misconception": "Thinking only retentivity matters for permanent magnets"}, {"option_key": "B", "hint": "Low retentivity means the material retains little magnetisation after removing H. A permanent magnet needs strong residual magnetisation.", "misconception": "Thinking only coercivity matters for permanent magnets"}, {"option_key": "D", "hint": "Low retentivity and low coercivity describe soft magnetic materials (like soft iron) used in electromagnets and transformers, not permanent magnets.", "misconception": "Confusing properties of soft and hard magnetic materials"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The domain theory of ferromagnetism explains that in an unmagnetised ferromagnetic specimen:", "explanation": "In an unmagnetised ferromagnetic material, the substance is divided into small regions called domains, each magnetised to saturation along a particular direction. However, the domains are randomly oriented so that their net magnetic moment cancels out, resulting in zero overall magnetisation.", "correct_answer": "D", "concept_tags": ["domain-theory", "ferromagnetism", "unmagnetised-state"], "payload": {"question_id": "cuet-phy-magmat-materials-08", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "There are no magnetic domains present", "is_correct": false}, {"key": "B", "text": "All domains are aligned in the same direction", "is_correct": false}, {"key": "C", "text": "Domains exist but have zero individual magnetisation", "is_correct": false}, {"key": "D", "text": "Domains are randomly oriented, giving zero net magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Domains always exist in ferromagnetic materials below the Curie temperature. They are not created by external fields; they are intrinsic to the material.", "misconception": "Thinking domains are created only when an external field is applied"}, {"option_key": "B", "hint": "If all domains were aligned in the same direction, the material would be fully magnetised (saturated), not unmagnetised.", "misconception": "Confusing magnetised state with unmagnetised state"}, {"option_key": "C", "hint": "Each domain is magnetised to saturation internally due to exchange interactions between neighbouring atoms. The individual domain magnetisation is not zero.", "misconception": "Thinking individual domains are unmagnetised"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Soft iron is preferred for making electromagnet cores because it has:", "explanation": "Soft iron has low coercivity (easily magnetised and demagnetised) and low retentivity (does not retain much magnetisation when the current is switched off). It also has high permeability, allowing strong magnetisation under an applied field. These properties make it ideal for electromagnets, transformers, and relay cores.", "correct_answer": "B", "concept_tags": ["soft-magnetic-material", "electromagnet", "coercivity", "retentivity"], "payload": {"question_id": "cuet-phy-magmat-materials-09", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "High coercivity and high retentivity", "is_correct": false}, {"key": "B", "text": "Low coercivity and low retentivity", "is_correct": true}, {"key": "C", "text": "High coercivity and low retentivity", "is_correct": false}, {"key": "D", "text": "Low permeability and high coercivity", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "High coercivity and high retentivity describe hard magnetic materials used for permanent magnets (e.g., steel, Alnico), not electromagnet cores.", "misconception": "Confusing properties needed for permanent magnets vs electromagnets"}, {"option_key": "C", "hint": "High coercivity would make it difficult to demagnetise the core when the current is turned off, which is undesirable for an electromagnet.", "misconception": "Thinking high coercivity is beneficial for electromagnets"}, {"option_key": "D", "hint": "Low permeability would mean the material does not concentrate magnetic flux well, defeating the purpose of using a core. Electromagnet cores need high permeability.", "misconception": "Thinking low permeability is useful for electromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The relationship between relative permeability (μᵣ) and magnetic susceptibility (χ) is:", "explanation": "The relation between relative permeability and susceptibility is μᵣ = 1 + χ. This follows from B = μ₀(H + M) = μ₀H(1 + χ) = μ₀μᵣH. For diamagnetic materials (χ < 0), μᵣ < 1; for paramagnetic (χ > 0, small), μᵣ > 1 (slightly); for ferromagnetic (χ >> 1), μᵣ >> 1.", "correct_answer": "A", "concept_tags": ["permeability-susceptibility-relation", "mu-r", "chi"], "payload": {"question_id": "cuet-phy-magmat-materials-10", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "μᵣ = 1 + χ", "is_correct": true}, {"key": "B", "text": "μᵣ = 1 − χ", "is_correct": false}, {"key": "C", "text": "μᵣ = χ", "is_correct": false}, {"key": "D", "text": "μᵣ = 1/χ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The correct formula uses addition, not subtraction. B = μ₀(H + M) gives μᵣ = 1 + M/H = 1 + χ.", "misconception": "Sign error in the permeability-susceptibility relation"}, {"option_key": "C", "hint": "If μᵣ = χ, then for diamagnetic materials (χ < 0), μᵣ would be negative, which is physically impossible for permeability.", "misconception": "Omitting the additive constant 1 in the relation"}, {"option_key": "D", "hint": "μᵣ = 1/χ would make permeability inversely related to susceptibility. For paramagnetic materials with very small χ, this would give enormously large μᵣ, which is incorrect.", "misconception": "Confusing the mathematical relationship between μᵣ and χ"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A ferromagnetic material has a susceptibility of 4999 at 300 K. If the Curie temperature of this material is 600 K, what is its approximate susceptibility at 900 K?", "explanation": "Above the Curie temperature, the material becomes paramagnetic and follows the Curie–Weiss law: χ = C/(T − Tc). At 300 K (below Tc), the material is ferromagnetic with χ = 4999. We use the Curie constant from this data: C = χ(T − Tc) is not directly applicable below Tc. However, at T = 300 K, using Curie–Weiss form approximately: C ≈ χ × (T − Tc) isn''t valid below Tc. Instead, above Tc, the Curie constant C can be estimated. For T >> Tc, we use the fact that just above Tc, C = χ_para × (T − Tc). From the given ferromagnetic χ at 300 K, the Curie constant C ≈ 4999 × 300 = 1.5 × 10⁶ (using Curie law approximation). Above Tc: χ = C/(T − Tc) = 1.5 × 10⁶/(900 − 600) = 1.5 × 10⁶/300 = 5000. But more correctly, since the material obeys Curie–Weiss law above Tc: χ = C/(T − Tc), and using the paramagnetic Curie constant from the high-temperature behaviour, χ at 900 K = C/(900 − 600) = C/300. Given the NEET-level approach: if χ ∝ 1/(T − Tc) above Curie temperature, and the problem gives χ at 300 K as a reference, the answer works out to approximately 5.", "correct_answer": "C", "concept_tags": ["curie-weiss-law", "susceptibility-temperature", "ferromagnetic-transition"], "payload": {"question_id": "cuet-phy-magmat-materials-11", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "4999", "is_correct": false}, {"key": "B", "text": "2500", "is_correct": false}, {"key": "C", "text": "5", "is_correct": true}, {"key": "D", "text": "0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 900 K the material is above its Curie temperature (600 K) and is paramagnetic with drastically reduced susceptibility. It cannot maintain ferromagnetic-level χ.", "misconception": "Ignoring the phase transition at Curie temperature"}, {"option_key": "B", "hint": "Simple halving would imply a linear dependence, which does not account for the transition from ferromagnetic to paramagnetic state at Tc.", "misconception": "Assuming a simple proportional decrease in susceptibility"}, {"option_key": "D", "hint": "Above Tc the material is paramagnetic, not non-magnetic. It still has a positive susceptibility, just much smaller than in the ferromagnetic state.", "misconception": "Thinking the material becomes completely non-magnetic above Tc"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The area enclosed by the hysteresis loop of a ferromagnetic material represents:", "explanation": "The area of the B-H hysteresis loop gives the energy dissipated (as heat) per unit volume of the material per cycle of magnetisation. This energy loss occurs because work must be done to move domain walls and rotate domains against internal friction during each cycle. Materials with a larger hysteresis loop area have greater energy loss per cycle.", "correct_answer": "D", "concept_tags": ["hysteresis-loop", "energy-loss", "B-H-curve", "domain-wall-motion"], "payload": {"question_id": "cuet-phy-magmat-materials-12", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "The retentivity of the material", "is_correct": false}, {"key": "B", "text": "The coercivity of the material", "is_correct": false}, {"key": "C", "text": "The permeability of the material", "is_correct": false}, {"key": "D", "text": "The energy dissipated per unit volume per cycle of magnetisation", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the y-intercept (B value at H = 0) on the hysteresis loop, not the area enclosed by it.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "B", "hint": "Coercivity is the x-intercept (H value at B = 0) on the hysteresis loop, representing a specific field value, not the enclosed area.", "misconception": "Confusing a point on the loop with the area of the loop"}, {"option_key": "C", "hint": "Permeability is related to the slope of the B-H curve (μ = B/H), not the area enclosed by the hysteresis loop.", "misconception": "Confusing the slope of B-H curve with loop area"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Diamagnetic substances are weakly repelled by a strong magnet.\nReason (R): The magnetic susceptibility of diamagnetic substances is small and negative.", "explanation": "Both the Assertion and Reason are correct, and R correctly explains A. Diamagnetic materials have χ < 0 (small negative value), which means the induced magnetisation opposes the applied field. This opposition results in a weak repulsive force when placed near a magnet. The negative susceptibility is the direct cause of the repulsion.", "correct_answer": "A", "concept_tags": ["diamagnetic", "susceptibility-negative", "repulsion", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmat-materials-13", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The negative susceptibility directly causes the opposing magnetisation, which produces the repulsive force. R is not merely a coincidental fact—it is the fundamental reason for the repulsion.", "misconception": "Failing to see the causal link between negative χ and repulsion"}, {"option_key": "C", "hint": "The Reason is factually correct. Diamagnetic materials do have small negative susceptibility (typically −10⁻⁵).", "misconception": "Doubting the sign of diamagnetic susceptibility"}, {"option_key": "D", "hint": "The Assertion is factually correct. Diamagnetic substances like bismuth are indeed weakly repelled by magnets, which is experimentally verifiable.", "misconception": "Thinking diamagnetic materials are attracted, not repelled"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The susceptibility of a ferromagnetic material is independent of temperature below its Curie temperature.\nReason (R): Ferromagnetic materials have large magnetic domains that align spontaneously due to exchange interaction.", "explanation": "The Assertion is incorrect. The susceptibility of a ferromagnetic material does depend on temperature even below the Curie temperature—it generally increases as temperature approaches Tc from below. The Reason is correct: ferromagnetic materials do possess domains where atomic moments are aligned by exchange interactions. Since A is false but R is true, the answer is D.", "correct_answer": "D", "concept_tags": ["ferromagnetic-susceptibility", "temperature-dependence", "domain-theory", "exchange-interaction"], "payload": {"question_id": "cuet-phy-magmat-materials-14", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion is false. Ferromagnetic susceptibility does change with temperature below Tc; it is not constant. It increases as T approaches Tc.", "misconception": "Believing ferromagnetic susceptibility is temperature-independent below Tc"}, {"option_key": "B", "hint": "Since the Assertion is incorrect, options A and B (which require A to be correct) are both eliminated.", "misconception": "Not carefully evaluating the truth of the Assertion"}, {"option_key": "C", "hint": "The Reason is correct. Exchange interaction is the quantum mechanical effect responsible for spontaneous domain alignment in ferromagnets.", "misconception": "Doubting the existence of exchange interaction in ferromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Diamagnetic material\n(Q) Paramagnetic material\n(R) Ferromagnetic material\n(S) Curie temperature\n\nColumn II:\n(1) χ >> 1\n(2) χ is small and negative\n(3) Temperature above which ferromagnet becomes paramagnetic\n(4) χ is small and positive", "explanation": "P-Diamagnetic material has χ small and negative → (2). Q-Paramagnetic material has χ small and positive → (4). R-Ferromagnetic material has χ >> 1 → (1). S-Curie temperature is the temperature above which a ferromagnet becomes paramagnetic → (3). So the correct matching is P→2, Q→4, R→1, S→3.", "correct_answer": "B", "concept_tags": ["magnetic-classification", "susceptibility", "curie-temperature", "match-the-following"], "payload": {"question_id": "cuet-phy-magmat-materials-15", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "text": "P→4, Q→2, R→1, S→3", "is_correct": false}, {"key": "D", "text": "P→2, Q→4, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This incorrectly assigns χ >> 1 to paramagnetic materials and χ small and positive to ferromagnetic materials. Paramagnetic χ is small and positive, while ferromagnetic χ is very large.", "misconception": "Swapping the susceptibility values of paramagnetic and ferromagnetic materials"}, {"option_key": "C", "hint": "This swaps paramagnetic and diamagnetic. Diamagnetic χ is negative (repelled), while paramagnetic χ is positive (attracted).", "misconception": "Confusing the sign of susceptibility for dia- and paramagnetic materials"}, {"option_key": "D", "hint": "This incorrectly matches R (ferromagnetic material) with (3) Curie temperature definition, and S (Curie temperature) with (1) χ >> 1. Curie temperature is a temperature, not a susceptibility value.", "misconception": "Confusing the property of a material with the definition of Curie temperature"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) High retentivity, high coercivity\n(Q) Low retentivity, low coercivity, high permeability\n(R) Narrow hysteresis loop\n(S) Wide hysteresis loop\n\nColumn II:\n(1) Electromagnet core material\n(2) Permanent magnet material\n(3) Low hysteresis loss per cycle\n(4) High hysteresis loss per cycle", "explanation": "P-High retentivity and high coercivity → (2) Permanent magnet material (hard magnets like steel, Alnico). Q-Low retentivity, low coercivity, high permeability → (1) Electromagnet core material (soft iron). R-Narrow hysteresis loop → (3) Low hysteresis loss per cycle (less area enclosed). S-Wide hysteresis loop → (4) High hysteresis loss per cycle (more area enclosed).", "correct_answer": "C", "concept_tags": ["hysteresis-loop", "permanent-magnet", "electromagnet", "soft-hard-materials", "match-the-following"], "payload": {"question_id": "cuet-phy-magmat-materials-16", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "analyze", "options": [{"key": "A", "text": "P→1, Q→2, R→4, S→3", "is_correct": false}, {"key": "B", "text": "P→2, Q→1, R→4, S→3", "is_correct": false}, {"key": "C", "text": "P→2, Q→1, R→3, S→4", "is_correct": true}, {"key": "D", "text": "P→1, Q→2, R→3, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps permanent magnet and electromagnet assignments. High retentivity and coercivity suit permanent magnets, not electromagnet cores.", "misconception": "Reversing the requirements for permanent magnets and electromagnets"}, {"option_key": "B", "hint": "While P→2 and Q→1 are correct, a narrow loop encloses less area and hence gives low (not high) hysteresis loss. R should map to (3), not (4).", "misconception": "Confusing narrow loop with high loss and wide loop with low loss"}, {"option_key": "D", "hint": "This incorrectly assigns P (high retentivity, high coercivity) to electromagnet cores. Electromagnets need easy magnetisation and demagnetisation (low coercivity).", "misconception": "Confusing the properties required for permanent magnets vs electromagnets"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Diamagnetic materials have their magnetic susceptibility nearly independent of temperature.", "explanation": "This statement is TRUE. Diamagnetic susceptibility arises from the orbital motion of electrons (Lenz''s law at the atomic level) and does not depend on thermal agitation of atomic magnetic moments (since there are no permanent atomic moments to align). Therefore, diamagnetic susceptibility is essentially independent of temperature, unlike paramagnetic susceptibility which follows Curie''s law (χ ∝ 1/T).", "correct_answer": "A", "concept_tags": ["diamagnetic", "temperature-independence", "susceptibility"], "payload": {"question_id": "cuet-phy-magmat-materials-17", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Diamagnetic susceptibility does not arise from permanent dipole alignment (which would be temperature-dependent). It originates from induced effects in electron orbits, making it largely temperature-independent.", "misconception": "Confusing diamagnetic temperature behaviour with paramagnetic Curie''s law behaviour"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field lines inside a diamagnetic material are more concentrated compared to the surrounding vacuum.", "explanation": "This statement is FALSE. In a diamagnetic material, the magnetic field lines are less concentrated (farther apart) compared to vacuum because the material weakly opposes the applied field (μᵣ < 1, χ < 0). The induced magnetisation is opposite to the applied field, reducing the total field inside. In contrast, paramagnetic and ferromagnetic materials concentrate field lines inside them.", "correct_answer": "B", "concept_tags": ["diamagnetic", "field-lines", "flux-density", "permeability"], "payload": {"question_id": "cuet-phy-magmat-materials-18", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Diamagnetic materials have μᵣ < 1, which means B inside is less than B in vacuum. Field lines are expelled from diamagnetic materials, not concentrated.", "misconception": "Thinking all materials concentrate magnetic field lines"}, {"option_key": "C", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}, {"option_key": "D", "hint": "This is a placeholder option and is not a valid answer.", "misconception": "N/A"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The magnetising field (H) required to reduce the residual magnetisation of a ferromagnetic material to zero is called _____.", "explanation": "The answer is coercivity (also called coercive force). On the hysteresis loop, after removing the external field (H = 0), the material retains some magnetisation (retentivity). To bring B back to zero, a reverse magnetising field must be applied. The magnitude of this reverse field is called the coercivity. Materials with high coercivity are hard to demagnetise and are used for permanent magnets.", "correct_answer": "C", "concept_tags": ["coercivity", "hysteresis", "demagnetisation", "fill-in-blanks"], "payload": {"question_id": "cuet-phy-magmat-materials-19", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "remember", "options": [{"key": "A", "text": "Retentivity", "is_correct": false}, {"key": "B", "text": "Susceptibility", "is_correct": false}, {"key": "C", "text": "Coercivity", "is_correct": true}, {"key": "D", "text": "Permeability", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Retentivity is the magnetisation remaining when H is zero, not the field needed to remove it. These are consecutive steps on the hysteresis loop.", "misconception": "Confusing retentivity (B at H = 0) with coercivity (H at B = 0)"}, {"option_key": "B", "hint": "Susceptibility (χ = M/H) is the ratio of magnetisation to magnetising field. It describes how easily a material is magnetised, not the demagnetising field.", "misconception": "Confusing susceptibility with coercivity"}, {"option_key": "D", "hint": "Permeability (μ) relates B to H as B = μH. It is a material property describing flux density per unit field, not the demagnetising field value.", "misconception": "Confusing permeability with coercivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-materials", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A transformer core is being designed for a power supply operating at 50 Hz. The engineer must choose between soft iron (narrow hysteresis loop, area = 50 J/m³ per cycle) and carbon steel (wide hysteresis loop, area = 5000 J/m³ per cycle). If the core volume is 0.002 m³, what is the power loss due to hysteresis in the soft iron core, and why is it the preferred choice?", "explanation": "Hysteresis power loss = (area of hysteresis loop) × (volume) × (frequency). For soft iron: P = 50 × 0.002 × 50 = 5 W. For carbon steel: P = 5000 × 0.002 × 50 = 500 W. The soft iron core dissipates only 5 W compared to 500 W for carbon steel. Additionally, soft iron has high permeability and low coercivity, making it easy to magnetise and demagnetise repeatedly. This makes it the preferred material for transformer cores where the field reverses 50 times per second.", "correct_answer": "B", "concept_tags": ["hysteresis-loss", "transformer-core", "soft-iron", "power-dissipation", "scenario-based"], "payload": {"question_id": "cuet-phy-magmat-materials-20", "subtopic": "Magnetic Properties of Materials", "topic_name": "Magnetic Properties of Materials", "bloom_level": "apply", "options": [{"key": "A", "text": "0.5 W; preferred because it has high retentivity", "is_correct": false}, {"key": "B", "text": "5 W; preferred because of low hysteresis loss and easy magnetisation/demagnetisation", "is_correct": true}, {"key": "C", "text": "50 W; preferred because it has high coercivity", "is_correct": false}, {"key": "D", "text": "500 W; preferred because it retains magnetisation", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P = 50 × 0.002 × 50 = 5 W, not 0.5 W. Check the multiplication. Also, high retentivity is undesirable in transformer cores as it causes residual magnetisation.", "misconception": "Arithmetic error in calculating hysteresis loss and confusing permanent magnet properties with transformer requirements"}, {"option_key": "C", "hint": "The calculated power loss for soft iron is 5 W, not 50 W. Also, high coercivity makes demagnetisation difficult, which increases energy loss—the opposite of what is needed.", "misconception": "Incorrect calculation and confusing high coercivity with desirable transformer properties"}, {"option_key": "D", "hint": "500 W is the hysteresis loss for carbon steel, not soft iron. Retaining magnetisation (high retentivity) is a property of permanent magnets, not suitable for transformer cores.", "misconception": "Using the wrong material''s loss value and confusing permanent magnet properties with transformer requirements"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Biot-Savart law, the magnetic field dB due to a small current element Idl at a point P is proportional to:", "explanation": "The Biot-Savart law states dB = (μ₀/4π)(Idl × r̂)/r². The magnitude of dB is proportional to sinθ (from the cross product) and inversely proportional to r². Here θ is the angle between the current element dl and the position vector r pointing from the element to the point P.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "magnetic-field", "current-element"], "payload": {"question_id": "cuet-phy-magmov-biot-01", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "sinθ/r², where θ is the angle between dl and r", "is_correct": true}, {"key": "B", "text": "cosθ/r², where θ is the angle between dl and r", "is_correct": false}, {"key": "C", "text": "sinθ/r, where θ is the angle between dl and r", "is_correct": false}, {"key": "D", "text": "cosθ/r, where θ is the angle between dl and r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Biot-Savart law involves a cross product (Idl × r̂), which gives sinθ, not cosθ. The cosθ dependence appears in electrostatics (e.g., electric flux), not here.", "misconception": "Confusing cross product with dot product"}, {"option_key": "C", "hint": "The field falls off as 1/r², not 1/r. The inverse-square dependence is analogous to Coulomb''s law.", "misconception": "Incorrect distance dependence"}, {"option_key": "D", "hint": "This has both the wrong angular dependence (cosθ instead of sinθ) and the wrong distance dependence (1/r instead of 1/r²).", "misconception": "Multiple errors in Biot-Savart law recall"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at the centre of a circular loop of radius R carrying current I is:", "explanation": "Using the Biot-Savart law and integrating over the entire circular loop, every element dl is perpendicular to the position vector r (θ = 90°) and at a distance R from the centre. The integration gives B = μ₀I/(2R). This is a standard result frequently used in NEET problems.", "correct_answer": "B", "concept_tags": ["circular-loop", "magnetic-field-centre", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-02", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I/(4πR)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀IR²/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(4πR) would result from integrating only a quarter of the loop. The full circular loop gives μ₀I/(2R).", "misconception": "Incomplete integration of the loop"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the magnetic field due to a long straight conductor at perpendicular distance R, not at the centre of a circular loop.", "misconception": "Confusing straight wire formula with circular loop formula"}, {"option_key": "D", "hint": "This expression has incorrect dimensions. μ₀IR²/2 has units of T·m³, not Tesla. The correct formula is μ₀I/(2R).", "misconception": "Dimensional error in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A long straight wire carries a current of 10 A. The magnetic field at a perpendicular distance of 0.1 m from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight conductor, B = μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = (4π × 10⁻⁶)/(0.2π) = 2 × 10⁻⁵ T = 20 μT.", "correct_answer": "C", "concept_tags": ["straight-conductor", "magnetic-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-03", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "2 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁷ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Recheck the calculation: μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = 2 × 10⁻⁵ T.", "misconception": "Arithmetic error with powers of 10"}, {"option_key": "B", "hint": "This is 100 times too large. The denominator 2πd = 2π × 0.1 ≈ 0.628, and dividing 4π × 10⁻⁶ by this gives 2 × 10⁻⁵, not 2 × 10⁻⁴.", "misconception": "Error in handling decimal distance"}, {"option_key": "D", "hint": "This equals μ₀/2π, which would correspond to I = 1 A at d = 1 m. With I = 10 A and d = 0.1 m, the field is much larger.", "misconception": "Using default values instead of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law states that the line integral of magnetic field B around a closed loop equals:", "explanation": "Ampere''s circuital law states ∮B·dl = μ₀I_enclosed, where I_enclosed is the total current threading through the closed Amperian loop. This law is analogous to Gauss''s law in electrostatics and is most useful when the magnetic field has high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-magmov-biot-04", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the total current in the circuit", "is_correct": false}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "μ₀ε₀ times the rate of change of electric flux", "is_correct": false}, {"key": "D", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law considers only the current enclosed by (threading through) the Amperian loop, not the total current in the entire circuit.", "misconception": "Confusing enclosed current with total circuit current"}, {"option_key": "B", "hint": "The line integral ∮B·dl gives μ₀I_enclosed, not magnetic flux. Magnetic flux is the surface integral ∫B·dA.", "misconception": "Confusing line integral of B with surface integral of B"}, {"option_key": "C", "hint": "This is Maxwell''s displacement current term, which is an addition to Ampere''s law. The basic Ampere''s circuital law relates ∮B·dl to μ₀I_enclosed.", "misconception": "Confusing Ampere''s law with Maxwell''s modification"}]}}]'::jsonb, 'deploy-2026-03-05-b12');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular loop of radius 0.1 m carries a current of 5 A. The magnetic field on the axis of the loop at a distance of 0.1 m from the centre is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "Using B = μ₀IR²/[2(R² + x²)^(3/2)] with R = 0.1 m, x = 0.1 m, I = 5 A: R² + x² = 0.01 + 0.01 = 0.02, so (R² + x²)^(3/2) = (0.02)^(3/2) = (0.02)^1 × √0.02 = 0.02 × 0.1414 = 2.828 × 10⁻³. Then B = (4π × 10⁻⁷ × 5 × 0.01)/(2 × 2.828 × 10⁻³) = (2π × 10⁻⁸)/(5.656 × 10⁻³) = 6.28 × 10⁻⁸/5.656 × 10⁻³ ≈ 1.11 × 10⁻⁵ T ≈ 11.1 μT.", "correct_answer": "A", "concept_tags": ["circular-loop", "axial-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-05", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1.11 × 10⁻⁵ T", "is_correct": true}, {"key": "B", "text": "3.14 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "2.22 × 10⁻⁵ T", "is_correct": false}, {"key": "D", "text": "5.55 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the value of μ₀I/(2R) = the field at the centre. At x = R on the axis, the field is reduced by a factor of 1/(2√2) compared to the centre field.", "misconception": "Using centre formula instead of axial formula"}, {"option_key": "C", "hint": "This is exactly double the correct answer. Check the factor of 2 in the denominator of B = μ₀IR²/[2(R² + x²)^(3/2)].", "misconception": "Missing the factor of 2 in the denominator"}, {"option_key": "D", "hint": "This is half the correct answer. Check the evaluation of (R² + x²)^(3/2) carefully.", "misconception": "Error in computing (R² + x²)^(3/2)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a semicircular wire of radius R carrying current I is:", "explanation": "A semicircular arc subtends an angle π at the centre. The field due to a circular arc subtending angle φ at the centre is B = μ₀Iφ/(4πR). For a semicircle, φ = π, so B = μ₀Iπ/(4πR) = μ₀I/(4R). The direction is perpendicular to the plane of the semicircle, determined by the right-hand rule.", "correct_answer": "B", "concept_tags": ["semicircular-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-06", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A semicircle is half the loop, so its contribution is half: μ₀I/(4R).", "misconception": "Using full loop formula for semicircle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field due to a long straight wire at distance R. The semicircular arc formula is μ₀I/(4R).", "misconception": "Confusing straight wire formula with arc formula"}, {"option_key": "D", "hint": "μ₀I/(8R) would be the field due to a quarter-circle arc, not a semicircle. A semicircle subtends angle π, giving μ₀I/(4R).", "misconception": "Using quarter-circle result instead of semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a solenoid, B = μ₀nI where n = N/L = 1000/0.5 = 2000 turns/m. B = 4π × 10⁻⁷ × 2000 × 2 = 4π × 10⁻⁷ × 4000 = 16π × 10⁻⁴ = 16 × 3.14 × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.03 mT.", "correct_answer": "C", "concept_tags": ["solenoid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-07", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2.51 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "C", "text": "5.03 × 10⁻³ T", "is_correct": true}, {"key": "D", "text": "5.03 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is exactly half the correct answer, suggesting you used N = 1000 instead of n = N/L = 2000 turns/m, or missed the current value.", "misconception": "Using total turns instead of turns per unit length"}, {"option_key": "B", "hint": "This would correspond to n = 1000 and I = 1, indicating errors in both n and I. Use n = N/L = 2000 turns/m and I = 2 A.", "misconception": "Multiple calculation errors"}, {"option_key": "D", "hint": "This is off by a factor of 10. Check the power of 10 in your calculation: μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³.", "misconception": "Power of 10 arithmetic error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a quarter-circle arc of radius R carrying current I is:", "explanation": "A quarter-circle arc subtends an angle π/2 at the centre. Using the formula B = μ₀Iφ/(4πR) for an arc of angle φ: B = μ₀I(π/2)/(4πR) = μ₀I/(8R). The straight portions (if connected along radii) contribute zero field at the centre because the current element is parallel to the position vector (sin0° = 0).", "correct_answer": "D", "concept_tags": ["quarter-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-08", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A quarter arc is one-fourth of the loop, giving μ₀I/(8R).", "misconception": "Using full loop formula for quarter arc"}, {"option_key": "B", "hint": "μ₀I/(4R) is the field due to a semicircular arc (half loop). A quarter arc gives half of this value: μ₀I/(8R).", "misconception": "Confusing semicircle with quarter circle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field of a long straight wire at distance R. The arc formula uses the angle subtended, not the straight-wire formula.", "misconception": "Applying straight wire formula to a curved conductor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 500 turns, a mean radius of 0.2 m, and carries a current of 3 A. The magnetic field inside the toroid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a toroid, applying Ampere''s law: B × 2πr = μ₀NI, so B = μ₀NI/(2πr). B = (4π × 10⁻⁷ × 500 × 3)/(2π × 0.2) = (4π × 1.5 × 10⁻⁴)/(0.4π) = (6π × 10⁻⁴)/(0.4π) = 6 × 10⁻⁴/0.4 = 1.5 × 10⁻³ T = 1.5 mT.", "correct_answer": "B", "concept_tags": ["toroid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-09", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "3.0 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.5 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "7.5 × 10⁻⁴ T", "is_correct": false}, {"key": "D", "text": "1.5 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is double the correct value. You may have used r = 0.1 m instead of the given mean radius r = 0.2 m in B = μ₀NI/(2πr).", "misconception": "Using radius instead of diameter, or halving the radius"}, {"option_key": "C", "hint": "This is half the correct answer. Check if you accidentally doubled the radius or halved the current in your calculation.", "misconception": "Arithmetic error in substitution"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 500 × 3 = 6π × 10⁻⁴, and dividing by 2π × 0.2 = 0.4π gives 1.5 × 10⁻³.", "misconception": "Power of 10 error in computation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric coplanar circular loops have radii R and 2R. The smaller loop carries current I in the anticlockwise direction and the larger loop carries current 2I in the clockwise direction, as seen from the same side. The magnetic field at the common centre is:", "explanation": "Field due to smaller loop (anticlockwise, out of plane): B₁ = μ₀I/(2R), directed outward. Field due to larger loop (clockwise, into plane): B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed inward. Since B₁ and B₂ are equal in magnitude but opposite in direction, the net field at the centre is zero.", "correct_answer": "A", "concept_tags": ["concentric-loops", "superposition", "magnetic-field-direction"], "payload": {"question_id": "cuet-phy-magmov-biot-10", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/R, directed into the plane", "is_correct": false}, {"key": "D", "text": "3μ₀I/(4R), directed out of the plane", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This ignores the contribution of the larger loop. Both loops contribute fields at the centre; you must find the vector sum. The two fields are equal and opposite, giving zero.", "misconception": "Considering only the smaller loop"}, {"option_key": "C", "hint": "The magnitudes are B₁ = μ₀I/(2R) (out) and B₂ = μ₀(2I)/(4R) = μ₀I/(2R) (in). These cancel out; they do not add to μ₀I/R.", "misconception": "Adding magnitudes instead of using vector directions"}, {"option_key": "D", "hint": "This does not correspond to any correct combination of the two fields. Compute each field using B = μ₀I/(2R) and apply superposition with correct directions.", "misconception": "Error in applying superposition principle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire is bent into a shape consisting of a semicircular arc of radius R connected to two straight segments, each extending radially from the ends of the arc to a point at distance 2R from the centre, and then connected by another semicircular arc of radius 2R (same centre). A current I flows through this composite loop. The magnetic field at the common centre is:", "explanation": "The straight radial segments contribute zero field at the centre because for them, dl is parallel to r̂ (sinθ = 0). The inner semicircle of radius R contributes B₁ = μ₀I/(4R) (using the semicircle formula μ₀I/(4R), directed out of the plane, say). The outer semicircle of radius 2R contributes B₂ = μ₀I/(4 × 2R) = μ₀I/(8R) in the opposite direction (since current flows in the opposite sense around the centre). Net field = μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), directed out of the plane.", "correct_answer": "C", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "biot-savart-law"], "payload": {"question_id": "cuet-phy-magmov-biot-11", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "B", "text": "3μ₀I/(8R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/(8R), directed out of the plane", "is_correct": true}, {"key": "D", "text": "3μ₀I/(4R), directed into the plane", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the field due to only the inner semicircular arc. You must also subtract the contribution of the outer semicircular arc, which opposes the inner one.", "misconception": "Ignoring the contribution of the outer semicircular arc"}, {"option_key": "B", "hint": "3μ₀I/(8R) would result from adding the two semicircular contributions instead of subtracting. The current traverses the two arcs in opposite senses relative to the centre, so the fields oppose each other.", "misconception": "Adding fields instead of subtracting due to opposite current directions"}, {"option_key": "D", "hint": "The magnitude and direction are both incorrect. The net field is μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), and its direction is that of the larger contribution (inner arc).", "misconception": "Errors in both magnitude and direction determination"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A comparison between Biot-Savart law and Coulomb''s law shows that both:", "explanation": "Both the Biot-Savart law (dB = μ₀Idl×r̂/(4πr²)) and Coulomb''s law (E = q r̂/(4πε₀r²)) exhibit an inverse-square dependence on distance. However, the Biot-Savart law involves a cross product (giving an angular dependence and a field perpendicular to the plane of dl and r), while Coulomb''s law produces a field along the line joining the source and point. Both also have a similar constant structure: μ₀/4π in Biot-Savart and 1/4πε₀ in Coulomb''s law.", "correct_answer": "D", "concept_tags": ["biot-savart-law", "coulomb-law", "comparison", "inverse-square"], "payload": {"question_id": "cuet-phy-magmov-biot-12", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Produce fields along the line joining source and field point", "is_correct": false}, {"key": "B", "text": "Are valid only for static charges", "is_correct": false}, {"key": "C", "text": "Involve a dot product between source vector and displacement", "is_correct": false}, {"key": "D", "text": "Obey the inverse-square law of distance dependence", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives a field along the line joining source and point, but Biot-Savart law gives a field perpendicular to the plane containing dl and r (due to the cross product).", "misconception": "Assuming both laws give fields in the same direction relative to source"}, {"option_key": "B", "hint": "Biot-Savart law deals with moving charges (current), not static charges. Coulomb''s law is for static charges. They are not both valid for the same scenario.", "misconception": "Confusing the domain of applicability of the two laws"}, {"option_key": "C", "hint": "Biot-Savart law involves a cross product (dl × r̂), not a dot product. This is a key difference from Coulomb''s law.", "misconception": "Confusing cross product with dot product in Biot-Savart law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field outside an ideal solenoid is zero. Reason (R): Applying Ampere''s circuital law to a rectangular Amperian loop with one side inside and one side outside the solenoid, the contribution from the outside segment is zero because the field there is zero.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. For an ideal (infinitely long) solenoid, using Ampere''s law with a rectangular loop: ∮B·dl = B_inside × l + 0 + B_outside × l + 0 = μ₀nIl. Since the field is confined inside (by symmetry and superposition arguments), B_outside = 0, and B_inside = μ₀nI. The Reason correctly describes how Ampere''s law is applied with the field outside being zero.", "correct_answer": "A", "concept_tags": ["solenoid", "ampere-law", "ideal-solenoid", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-biot-13", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly describes the Amperian loop analysis that leads to the conclusion in the Assertion. It is not an unrelated fact; it is the specific explanation for why B = 0 outside.", "misconception": "Failing to see the direct causal link between Ampere''s law application and the result"}, {"option_key": "C", "hint": "The Reason is a correct description of how Ampere''s law is applied to an ideal solenoid. The zero field outside is both used as input (from symmetry) and confirmed by the law.", "misconception": "Incorrectly judging the Reason as false"}, {"option_key": "D", "hint": "The Assertion is well-established physics: an ideal infinite solenoid has zero external field. This is a standard NCERT result.", "misconception": "Incorrectly thinking a solenoid produces field outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Biot-Savart law can be used to determine the magnetic field due to any arbitrary current distribution. Reason (R): Ampere''s circuital law can be conveniently used to calculate magnetic fields only when the system has sufficient symmetry.", "explanation": "Both A and R are correct statements. Biot-Savart law is a general law applicable to any current configuration (though integration may be complex). Ampere''s law, while always true, is practically useful for calculating B only in highly symmetric situations (infinite straight wire, solenoid, toroid). However, R is NOT the explanation for A. The reason Biot-Savart law is general is because it directly integrates the contribution of each current element, not because Ampere''s law has symmetry limitations.", "correct_answer": "B", "concept_tags": ["biot-savart-law", "ampere-law", "symmetry", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-biot-14", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the limitation of Ampere''s law (needing symmetry) does not explain why Biot-Savart law is general. They are independent facts about two different laws.", "misconception": "Assuming that one law''s limitation automatically explains another law''s generality"}, {"option_key": "C", "hint": "The Reason is a correct statement. Ampere''s law is indeed only practically useful for field calculation when high symmetry exists (e.g., infinite wire, solenoid, toroid).", "misconception": "Thinking Ampere''s law always allows easy field computation"}, {"option_key": "D", "hint": "The Assertion is correct. Biot-Savart law is indeed a general law that can be applied to any current distribution by integrating dB contributions from each element.", "misconception": "Thinking Biot-Savart law has limited applicability"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Long straight conductor carrying current I\n(Q) Circular loop of radius R at its centre\n(R) Solenoid with n turns per unit length\n(S) Toroid of mean radius r with N total turns\n\nColumn II:\n(1) B = μ₀nI\n(2) B = μ₀I/(2πd)\n(3) B = μ₀NI/(2πr)\n(4) B = μ₀I/(2R)", "explanation": "P-2: A long straight conductor produces B = μ₀I/(2πd) at perpendicular distance d. Q-4: At the centre of a circular loop, B = μ₀I/(2R). R-1: Inside an ideal solenoid, B = μ₀nI. S-3: Inside a toroid, B = μ₀NI/(2πr). The correct matching is P-2, Q-4, R-1, S-3.", "correct_answer": "C", "concept_tags": ["magnetic-field-formulas", "straight-conductor", "circular-loop", "solenoid", "toroid"], "payload": {"question_id": "cuet-phy-magmov-biot-15", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "B", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": true}, {"key": "D", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P-1 would assign B = μ₀nI to a straight conductor, but that is the solenoid formula. A straight conductor gives B = μ₀I/(2πd).", "misconception": "Confusing solenoid formula with straight wire formula"}, {"option_key": "B", "hint": "Q-3 assigns the toroid formula to the circular loop. The circular loop at centre gives B = μ₀I/(2R), not μ₀NI/(2πr).", "misconception": "Swapping circular loop and toroid formulas"}, {"option_key": "D", "hint": "P-3 assigns the toroid formula to a straight conductor and S-2 assigns the straight wire formula to the toroid. These are swapped.", "misconception": "Interchanging straight conductor and toroid formulas"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field on the axis of a circular loop at distance x >> R from centre\n(Q) Magnetic field at the centre of a circular arc subtending angle θ\n(R) Magnetic field inside a solenoid at a point near its end\n(S) Magnetic field at the centre of two concentric coplanar loops of radii R and 2R carrying equal current I in the same direction\n\nColumn II:\n(1) μ₀Iθ/(4πR)\n(2) Approximately μ₀nI/2\n(3) 3μ₀I/(4R)\n(4) Varies as 1/x³ (magnetic dipole behaviour)", "explanation": "P-4: For x >> R, B = μ₀IR²/[2(R² + x²)^(3/2)] ≈ μ₀IR²/(2x³), which varies as 1/x³ like a magnetic dipole. Q-1: The field at the centre of an arc of angle θ is B = μ₀Iθ/(4πR). R-2: At the end of a solenoid, the field is approximately half the interior value, i.e., ≈μ₀nI/2. S-3: B = μ₀I/(2R) + μ₀I/(2×2R) = μ₀I/(2R) + μ₀I/(4R) = 3μ₀I/(4R).", "correct_answer": "D", "concept_tags": ["axial-field", "magnetic-dipole", "arc-formula", "solenoid-end", "superposition"], "payload": {"question_id": "cuet-phy-magmov-biot-16", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "C", "text": "P-4, Q-3, R-2, S-1", "is_correct": false}, {"key": "D", "text": "P-4, Q-1, R-2, S-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R-3 assigns 3μ₀I/(4R) to the solenoid end field, but that expression involves R (loop radius), not the solenoid parameters. The solenoid end field is ≈μ₀nI/2.", "misconception": "Confusing solenoid end field with concentric loop superposition"}, {"option_key": "B", "hint": "P-1 assigns the arc formula to the far-axis field. The far-axis field follows the dipole 1/x³ dependence, not the arc formula.", "misconception": "Mixing up axial field behaviour with arc field formula"}, {"option_key": "C", "hint": "Q-3 assigns 3μ₀I/(4R) to an arc, but that result comes from superposition of two concentric loops, not a single arc. The arc formula is μ₀Iθ/(4πR).", "misconception": "Confusing arc formula with superposition result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This is TRUE. By applying Ampere''s circuital law to an ideal (infinitely long) solenoid, the magnetic field inside is found to be B = μ₀nI, which is constant and does not depend on the position inside the solenoid. The field is directed along the axis of the solenoid, as determined by the right-hand rule. Outside the ideal solenoid, the field is zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-field", "ampere-law"], "payload": {"question_id": "cuet-phy-magmov-biot-17", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a well-known result from Ampere''s law. The field B = μ₀nI is independent of position inside the solenoid and is directed along the axis.", "misconception": "Thinking the field varies inside a solenoid or is not axial"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field at a point on the axis of a current-carrying circular loop is always perpendicular to the axis of the loop.", "explanation": "This is FALSE. The magnetic field at any point on the axis of a current-carrying circular loop is directed along the axis of the loop (either towards or away from the loop depending on current direction), not perpendicular to it. By symmetry, the perpendicular components from opposite current elements cancel out, leaving only the axial component. The field is given by B = μ₀IR²/[2(R² + x²)^(3/2)] along the axis.", "correct_answer": "B", "concept_tags": ["circular-loop", "axial-field", "symmetry", "field-direction"], "payload": {"question_id": "cuet-phy-magmov-biot-18", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field on the axis is along the axis, not perpendicular to it. By symmetry, the perpendicular components cancel. Think of the right-hand thumb rule: curling fingers in the direction of current, the thumb points along the axis.", "misconception": "Confusing axial direction with perpendicular direction for on-axis field"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "If a circular coil of 200 turns and radius 0.05 m carries a current of 0.5 A, the magnetic field at its centre is _____ T. (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a flat coil of N turns, the magnetic field at the centre is B = μ₀NI/(2R). Substituting: B = (4π × 10⁻⁷ × 200 × 0.5)/(2 × 0.05) = (4π × 10⁻⁷ × 100)/0.1 = (4π × 10⁻⁵)/0.1 = 4π × 10⁻⁴ = 12.57 × 10⁻⁴ T ≈ 1.26 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["circular-coil", "multiple-turns", "magnetic-field-centre", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-biot-19", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻⁴", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻³", "is_correct": true}, {"key": "D", "text": "6.28 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6.28 × 10⁻³ is five times too large. Check if you used the correct radius: R = 0.05 m, not 0.01 m.", "misconception": "Using incorrect radius value"}, {"option_key": "B", "hint": "1.26 × 10⁻⁴ is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 200 × 0.5 = 4π × 10⁻⁵, and dividing by 2R = 0.1 gives 4π × 10⁻⁴ ≈ 1.26 × 10⁻³.", "misconception": "Power of 10 error"}, {"option_key": "D", "hint": "6.28 × 10⁻⁴ = 2π × 10⁻⁴, which suggests using N = 100 or I = 0.25. With the given values, B = 4π × 10⁻⁴ ≈ 1.26 × 10⁻³ T.", "misconception": "Halving one of the given quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An MRI (Magnetic Resonance Imaging) machine uses a large solenoid to produce a strong, uniform magnetic field for medical imaging. A particular MRI solenoid is 2 m long, has 10,000 turns, and produces a magnetic field of 1.5 T inside. What is the current flowing through the solenoid? (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a solenoid, B = μ₀nI, where n = N/L = 10000/2 = 5000 turns/m. Rearranging for current: I = B/(μ₀n) = 1.5/(4π × 10⁻⁷ × 5000) = 1.5/(2π × 10⁻³) = 1.5/(6.283 × 10⁻³) ≈ 238.7 A ≈ 239 A. This illustrates why MRI machines require superconducting coils to sustain such large currents without resistive heating.", "correct_answer": "D", "concept_tags": ["solenoid", "MRI-application", "ampere-law", "numerical-problem", "real-world"], "payload": {"question_id": "cuet-phy-magmov-biot-20", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "23.9 A", "is_correct": false}, {"key": "B", "text": "119 A", "is_correct": false}, {"key": "C", "text": "477 A", "is_correct": false}, {"key": "D", "text": "239 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "23.9 A is ten times too small. Check n = N/L = 10000/2 = 5000 turns/m, not 50000. Then I = 1.5/(4π × 10⁻⁷ × 5000) ≈ 239 A.", "misconception": "Error in calculating turns per unit length"}, {"option_key": "B", "hint": "119 A is half the correct answer. This could result from using L = 1 m instead of 2 m (making n = 10000 instead of 5000), then dividing again incorrectly.", "misconception": "Using incorrect length or extra factor of 2"}, {"option_key": "C", "hint": "477 A is double the correct answer, suggesting n = N/L was calculated as 2500 instead of 5000, or an error in length. Use L = 2 m to get n = 5000.", "misconception": "Halving the turns per unit length"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A cyclotron is used to accelerate:", "explanation": "A cyclotron is used to accelerate charged particles such as protons, deuterons, and alpha particles. It cannot accelerate neutral particles (no Lorentz force) or electrons (their small mass causes relativistic effects at modest energies, making the cyclotron frequency condition invalid). The device uses a combination of electric and magnetic fields to accelerate charged particles to high energies.", "correct_answer": "B", "concept_tags": ["cyclotron", "charged-particles", "particle-accelerator"], "payload": {"question_id": "cuet-phy-magmov-devices-01", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Electrons", "is_correct": false}, {"key": "B", "text": "Protons and deuterons", "is_correct": true}, {"key": "C", "text": "Neutral atoms", "is_correct": false}, {"key": "D", "text": "Neutrons", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small mass (9.1 x 10^-31 kg), so they quickly reach relativistic speeds where their mass increases significantly, violating the constant cyclotron frequency condition.", "misconception": "Thinking cyclotron works for all charged particles regardless of mass"}, {"option_key": "C", "hint": "Neutral atoms have no net charge, so they experience no Lorentz force (F = qv x B = 0) and cannot be accelerated by electric or magnetic fields.", "misconception": "Forgetting that cyclotron requires charged particles"}, {"option_key": "D", "hint": "Neutrons are uncharged particles. The cyclotron relies on the magnetic force (qvB) to bend particle paths, which is zero for neutral particles.", "misconception": "Confusing neutrons with charged particles"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The time period of a charged particle revolving in a cyclotron is independent of:", "explanation": "In a cyclotron, the time period T = 2πm/(qB). This expression shows that T depends only on mass (m), charge (q), and magnetic field (B). It does not depend on the speed or energy of the particle (non-relativistic case). This is the key principle that makes the cyclotron work -- particles take the same time per revolution regardless of their speed, allowing a fixed-frequency oscillating electric field to accelerate them.", "correct_answer": "C", "concept_tags": ["cyclotron-frequency", "time-period", "independence-of-speed"], "payload": {"question_id": "cuet-phy-magmov-devices-02", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Mass of the particle", "is_correct": false}, {"key": "B", "text": "Magnetic field strength", "is_correct": false}, {"key": "C", "text": "Speed of the particle", "is_correct": true}, {"key": "D", "text": "Charge of the particle", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The formula T = 2πm/(qB) explicitly contains mass m in the numerator, so the time period directly depends on mass.", "misconception": "Overlooking the mass dependence in the cyclotron frequency formula"}, {"option_key": "B", "hint": "Magnetic field B appears in the denominator of T = 2πm/(qB). Increasing B decreases the time period, so T depends on B.", "misconception": "Ignoring the role of magnetic field in determining the cyclotron period"}, {"option_key": "D", "hint": "Charge q is in the denominator of T = 2πm/(qB). A particle with larger charge has a shorter time period, so T does depend on charge.", "misconception": "Forgetting that charge influences the cyclotron frequency"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "To convert a galvanometer into a voltmeter, one should connect:", "explanation": "A galvanometer is converted into a voltmeter by connecting a high resistance in series with it. This limits the current through the galvanometer to its full-scale deflection current (Ig) when the desired maximum voltage V is applied. The required series resistance R = V/Ig - G, where G is the galvanometer resistance. The high series resistance ensures that the voltmeter draws negligible current from the circuit.", "correct_answer": "A", "concept_tags": ["galvanometer-conversion", "voltmeter", "series-resistance"], "payload": {"question_id": "cuet-phy-magmov-devices-03", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "A high resistance in series", "is_correct": true}, {"key": "B", "text": "A low resistance in series", "is_correct": false}, {"key": "C", "text": "A high resistance in parallel", "is_correct": false}, {"key": "D", "text": "A low resistance in parallel", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "A low resistance in series would barely increase the total resistance, so the galvanometer would still draw too much current and could be damaged. The resistance must be high to limit current to Ig.", "misconception": "Not understanding that a voltmeter must have very high resistance"}, {"option_key": "C", "hint": "A high resistance in parallel would have little effect since most current would still flow through the lower-resistance galvanometer. Parallel connection is used for ammeter conversion.", "misconception": "Confusing series and parallel configurations for meter conversion"}, {"option_key": "D", "hint": "A low resistance in parallel (shunt) is used to convert a galvanometer into an ammeter, not a voltmeter.", "misconception": "Confusing ammeter and voltmeter conversion methods"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a moving coil galvanometer, the restoring torque is provided by:", "explanation": "In a moving coil galvanometer, the coil experiences a deflecting torque (τ = NIAB) due to the magnetic field. The restoring torque is provided by a pair of phosphor-bronze springs (hair springs) attached to the coil. At equilibrium, the restoring torque (kθ) equals the deflecting torque (NIAB), giving θ = NIAB/k. The springs also serve as leads to carry current to and from the coil.", "correct_answer": "D", "concept_tags": ["moving-coil-galvanometer", "restoring-torque", "spring", "equilibrium"], "payload": {"question_id": "cuet-phy-magmov-devices-04", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "The magnetic field", "is_correct": false}, {"key": "B", "text": "Gravity", "is_correct": false}, {"key": "C", "text": "The soft iron core", "is_correct": false}, {"key": "D", "text": "The phosphor-bronze spring", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The magnetic field produces the deflecting torque (τ = NIAB), not the restoring torque. The restoring mechanism must oppose the deflection.", "misconception": "Confusing deflecting torque with restoring torque"}, {"option_key": "B", "hint": "Gravity is not used as the restoring mechanism in a moving coil galvanometer. The instrument can work in any orientation because springs provide the restoring torque.", "misconception": "Confusing with gravity-based instruments"}, {"option_key": "C", "hint": "The soft iron core makes the magnetic field radial (uniform in all positions of the coil) to ensure linear deflection, but it does not provide the restoring torque.", "misconception": "Confusing the role of the iron core with the spring"}]}}]'::jsonb, 'deploy-2026-03-05-b12');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A cyclotron''s oscillator frequency is 10 MHz. If the magnetic field is 0.5 T, the charge-to-mass ratio (q/m) of the particle being accelerated is approximately:", "explanation": "The cyclotron frequency is given by f = qB/(2πm), so q/m = 2πf/B. Substituting the values: q/m = 2π x 10 x 10^6 / 0.5 = 2 x 3.14 x 10^7 / 0.5 = 6.28 x 10^7 / 0.5 = 1.256 x 10^8 C/kg ≈ 1.26 x 10^8 C/kg. This is close to the q/m ratio of a proton (e/mp = 1.6 x 10^-19 / 1.67 x 10^-27 ≈ 0.96 x 10^8 C/kg), suggesting a slightly different ion.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "charge-to-mass-ratio", "numerical"], "payload": {"question_id": "cuet-phy-magmov-devices-05", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 x 10^7 C/kg", "is_correct": false}, {"key": "B", "text": "1.26 x 10^8 C/kg", "is_correct": true}, {"key": "C", "text": "3.14 x 10^8 C/kg", "is_correct": false}, {"key": "D", "text": "2.0 x 10^7 C/kg", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This value (6.28 x 10^7) equals 2πf but forgets to divide by B. The correct formula is q/m = 2πf/B, and you must divide by 0.5 T.", "misconception": "Forgetting to divide by the magnetic field B"}, {"option_key": "C", "hint": "This value (3.14 x 10^8) corresponds to dividing by B but using πf instead of 2πf, or an arithmetic error in the multiplication.", "misconception": "Incorrect substitution in the cyclotron frequency formula"}, {"option_key": "D", "hint": "This value is significantly off from the correct calculation. With f = 10^7 Hz and B = 0.5 T, q/m = 2π x 10^7 / 0.5 = 4π x 10^7 ≈ 1.26 x 10^8.", "misconception": "Major arithmetic error or using the wrong formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer has a resistance of 50 Ω and gives full-scale deflection for a current of 1 mA. To convert it into an ammeter of range 0 to 5 A, the shunt resistance required is:", "explanation": "To convert a galvanometer to an ammeter, a shunt resistance S is connected in parallel. Using the formula S = Ig x G/(I - Ig), where Ig = 1 mA = 0.001 A, G = 50 Ω, and I = 5 A: S = 0.001 x 50 / (5 - 0.001) = 0.05 / 4.999 ≈ 0.01 Ω. Since Ig << I, we can approximate S ≈ Ig x G / I = 0.001 x 50 / 5 = 0.01 Ω.", "correct_answer": "A", "concept_tags": ["galvanometer-to-ammeter", "shunt-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-devices-06", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "0.01 Ω", "is_correct": true}, {"key": "B", "text": "0.05 Ω", "is_correct": false}, {"key": "C", "text": "1.0 Ω", "is_correct": false}, {"key": "D", "text": "50 Ω", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "0.05 Ω = Ig x G = 0.001 x 50. This is the numerator of the formula but you must divide by (I - Ig) ≈ 5 to get the shunt value.", "misconception": "Using S = Ig x G instead of the complete formula S = Ig x G/(I - Ig)"}, {"option_key": "C", "hint": "1.0 Ω is too high for a shunt. The shunt must be much smaller than the galvanometer resistance to divert most current away from the coil.", "misconception": "Not understanding that shunt resistance should be very small"}, {"option_key": "D", "hint": "Using S = G = 50 Ω means equal resistance in parallel, which would only double the range, not increase it 5000 times.", "misconception": "Thinking the shunt should equal the galvanometer resistance"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The current sensitivity of a moving coil galvanometer can be increased by:", "explanation": "Current sensitivity Is = NAB/k, where N is the number of turns, A is the area of the coil, B is the magnetic field strength, and k is the torsional spring constant. To increase current sensitivity, we can increase N, A, or B, or decrease k (use a weaker spring). Increasing the spring constant k would decrease the sensitivity, not increase it.", "correct_answer": "C", "concept_tags": ["current-sensitivity", "galvanometer", "NAB-by-k"], "payload": {"question_id": "cuet-phy-magmov-devices-07", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "Increasing the spring constant k", "is_correct": false}, {"key": "B", "text": "Decreasing the number of turns N", "is_correct": false}, {"key": "C", "text": "Increasing the magnetic field strength B", "is_correct": true}, {"key": "D", "text": "Decreasing the area of the coil A", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since Is = NAB/k, increasing k (denominator) would decrease the sensitivity, making the galvanometer less sensitive to small currents.", "misconception": "Confusing direct and inverse proportionality in the sensitivity formula"}, {"option_key": "B", "hint": "N appears in the numerator of Is = NAB/k. Decreasing N would reduce sensitivity, not increase it.", "misconception": "Incorrectly identifying N as being in the denominator"}, {"option_key": "D", "hint": "Area A is in the numerator of Is = NAB/k. A larger coil area increases the torque for a given current, increasing sensitivity.", "misconception": "Thinking smaller area gives better sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A galvanometer of resistance 100 Ω gives full-scale deflection for a current of 10 mA. The resistance to be connected in series to convert it into a voltmeter of range 0-100 V is:", "explanation": "To convert a galvanometer to a voltmeter, a high resistance R is connected in series. Using R = V/Ig - G, where V = 100 V, Ig = 10 mA = 0.01 A, and G = 100 Ω: R = 100/0.01 - 100 = 10000 - 100 = 9900 Ω. The total resistance of the voltmeter becomes G + R = 10000 Ω, ensuring that only Ig flows when V is applied across it.", "correct_answer": "D", "concept_tags": ["galvanometer-to-voltmeter", "series-resistance", "numerical-problem"], "payload": {"question_id": "cuet-phy-magmov-devices-08", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "10000 Ω", "is_correct": false}, {"key": "B", "text": "1000 Ω", "is_correct": false}, {"key": "C", "text": "10 Ω", "is_correct": false}, {"key": "D", "text": "9900 Ω", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10000 Ω is V/Ig = 100/0.01, which is the total resistance needed. But the question asks for the series resistance R alone, so you must subtract G: R = 10000 - 100 = 9900 Ω.", "misconception": "Forgetting to subtract the galvanometer resistance G from V/Ig"}, {"option_key": "B", "hint": "1000 Ω would give a total resistance of 1100 Ω, limiting the voltmeter range to only V = Ig x (G + R) = 0.01 x 1100 = 11 V, not 100 V.", "misconception": "Arithmetic error or using wrong formula"}, {"option_key": "C", "hint": "10 Ω is far too small. With R = 10 Ω, total resistance = 110 Ω, giving range V = 0.01 x 110 = 1.1 V only.", "misconception": "Confusing voltmeter conversion with ammeter conversion (where low resistance is used)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The maximum kinetic energy of a charged particle emerging from a cyclotron of radius R, magnetic field B, charge q, and mass m is:", "explanation": "In a cyclotron, the charged particle moves in a circular path where the magnetic force provides centripetal force: qvB = mv^2/R, giving v = qBR/m. The maximum kinetic energy is KE = (1/2)mv^2 = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m). Here R is the radius of the largest semicircular path (the dee radius).", "correct_answer": "A", "concept_tags": ["cyclotron", "kinetic-energy", "maximum-energy", "dee-radius"], "payload": {"question_id": "cuet-phy-magmov-devices-09", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "q²B²R²/(2m)", "is_correct": true}, {"key": "B", "text": "qBR/(2m)", "is_correct": false}, {"key": "C", "text": "q²B²R²/(m)", "is_correct": false}, {"key": "D", "text": "qB²R²/(2m)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This expression has dimensions of velocity (m/s), not energy (kg m^2/s^2). The kinetic energy must involve squared terms of q, B, and R.", "misconception": "Confusing the expression for velocity with kinetic energy"}, {"option_key": "C", "hint": "This is twice the correct answer. KE = (1/2)mv^2 has the factor of 1/2, so the result should be q^2B^2R^2/(2m), not q^2B^2R^2/m.", "misconception": "Forgetting the factor of 1/2 in the kinetic energy formula"}, {"option_key": "D", "hint": "This expression is missing one factor of q. Since v = qBR/m, the KE = (1/2)m(qBR/m)^2 = q^2B^2R^2/(2m), requiring q squared.", "misconception": "Error in squaring the velocity expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The voltage sensitivity of a galvanometer of resistance G, having N turns of area A in magnetic field B with spring constant k is given by:", "explanation": "Voltage sensitivity Vs = deflection per unit voltage = θ/V. Since θ/I (current sensitivity) = NAB/k, and V = IR (where R is the total resistance = G for the galvanometer alone), we get Vs = θ/V = (θ/I) x (1/G) = NAB/(kG). Thus voltage sensitivity depends inversely on the galvanometer resistance, unlike current sensitivity.", "correct_answer": "C", "concept_tags": ["voltage-sensitivity", "galvanometer", "NAB-by-kG"], "payload": {"question_id": "cuet-phy-magmov-devices-10", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "NAB/k", "is_correct": false}, {"key": "B", "text": "NABk/G", "is_correct": false}, {"key": "C", "text": "NAB/(kG)", "is_correct": true}, {"key": "D", "text": "NAG/(kB)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "NAB/k is the current sensitivity (θ/I), not the voltage sensitivity. Voltage sensitivity = current sensitivity / G = NAB/(kG).", "misconception": "Confusing current sensitivity with voltage sensitivity"}, {"option_key": "B", "hint": "This expression has k in the numerator. Since higher spring constant k means lower deflection per unit current, k must be in the denominator.", "misconception": "Placing k incorrectly in the formula"}, {"option_key": "D", "hint": "This expression has G in the numerator and B in the denominator, both of which are inverted. Higher B gives more torque (hence more sensitivity), and higher G gives less voltage sensitivity.", "misconception": "Swapping the positions of B and G"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A proton is accelerated in a cyclotron with magnetic field 1.5 T. The radius of the dees is 0.5 m. The maximum kinetic energy gained by the proton is approximately (mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C):", "explanation": "Maximum KE = q^2B^2R^2/(2m). Substituting: KE = (1.6 x 10^-19)^2 x (1.5)^2 x (0.5)^2 / (2 x 1.67 x 10^-27) = (2.56 x 10^-38) x 2.25 x 0.25 / (3.34 x 10^-27) = (2.56 x 10^-38 x 0.5625) / (3.34 x 10^-27) = 1.44 x 10^-38 / 3.34 x 10^-27 = 4.31 x 10^-12 J. Converting to MeV: 4.31 x 10^-12 / 1.6 x 10^-13 ≈ 26.9 MeV ≈ 27 MeV.", "correct_answer": "C", "concept_tags": ["cyclotron", "maximum-kinetic-energy", "proton", "numerical-calculation"], "payload": {"question_id": "cuet-phy-magmov-devices-11", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "7 MeV", "is_correct": false}, {"key": "B", "text": "14 MeV", "is_correct": false}, {"key": "C", "text": "27 MeV", "is_correct": true}, {"key": "D", "text": "54 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "7 MeV is approximately 1/4 of the correct answer. Check if you used R = 0.25 m instead of 0.5 m, or missed squaring one of the terms.", "misconception": "Using R instead of R^2 in the kinetic energy formula"}, {"option_key": "B", "hint": "14 MeV is half the correct answer. Ensure you have squared both q and B correctly in q^2B^2R^2/(2m).", "misconception": "Forgetting to square one of the quantities"}, {"option_key": "D", "hint": "54 MeV is double the correct answer. Check that you included the factor of 2 in the denominator of KE = q^2B^2R^2/(2m).", "misconception": "Forgetting the factor of 1/2 in the kinetic energy expression"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A galvanometer of resistance 50 Ω and full-scale deflection current 2 mA is to be converted into an ammeter of range 0-10 A and a voltmeter of range 0-200 V. The ratio of shunt resistance to series resistance is:", "explanation": "For ammeter: S = Ig x G/(I - Ig) = 0.002 x 50/(10 - 0.002) ≈ 0.1/9.998 ≈ 0.01 Ω. For voltmeter: R = V/Ig - G = 200/0.002 - 50 = 100000 - 50 = 99950 Ω. Ratio S/R = 0.01/99950 ≈ 1 x 10^-7. Alternatively, S/R = [Ig x G/(I - Ig)] / [V/Ig - G] ≈ [Ig x G/I] / [V/Ig] = Ig^2 x G / (IV) = (0.002)^2 x 50 / (10 x 200) = 2 x 10^-7 / 2000 = 1 x 10^-7.", "correct_answer": "D", "concept_tags": ["ammeter-voltmeter-conversion", "shunt", "series-resistance", "ratio"], "payload": {"question_id": "cuet-phy-magmov-devices-12", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 x 10^-3", "is_correct": false}, {"key": "B", "text": "1 x 10^-5", "is_correct": false}, {"key": "C", "text": "1 x 10^-6", "is_correct": false}, {"key": "D", "text": "1 x 10^-7", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would imply the shunt is only 1000 times smaller than the series resistance. Given the huge difference in conversion (ammeter needs ~0.01 Ω, voltmeter needs ~100000 Ω), the ratio should be much smaller.", "misconception": "Rough estimation without proper calculation"}, {"option_key": "B", "hint": "Verify your calculation: S ≈ 0.01 Ω and R ≈ 99950 Ω. The ratio 0.01/99950 is approximately 10^-7, not 10^-5.", "misconception": "Arithmetic error in the order of magnitude"}, {"option_key": "C", "hint": "Close but off by a factor of 10. Carefully recalculate: S/R = 0.01/99950 ≈ 1.0 x 10^-7.", "misconception": "Small arithmetic or rounding error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The cyclotron frequency does not depend on the speed of the charged particle. Reason (R): In a cyclotron, as the particle gains speed, the radius of its circular path increases proportionally, keeping the time period constant.", "explanation": "Both the Assertion and Reason are correct, and the Reason correctly explains the Assertion. The cyclotron frequency f = qB/(2πm) is independent of speed. This is because when a particle gains energy and moves faster (v increases), it moves to a larger radius orbit (r = mv/(qB)), so r increases proportionally with v. Since T = 2πr/v = 2πm/(qB), the v cancels out, making the period constant. This is the fundamental principle that allows the cyclotron to use a fixed-frequency oscillating electric field.", "correct_answer": "A", "concept_tags": ["cyclotron-frequency", "radius-speed-relation", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-magmov-devices-13", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly explains why the frequency is independent of speed: the increase in radius exactly compensates for the increase in speed, so the time per revolution stays constant. This is a causal explanation.", "misconception": "Not recognizing the causal connection between the radius-speed relationship and constant frequency"}, {"option_key": "C", "hint": "The Reason is factually correct. In a cyclotron, r = mv/(qB), so r is directly proportional to v. The circumference (2πr) grows in proportion to v, keeping T = 2πr/v constant.", "misconception": "Doubting the relationship between radius and speed"}, {"option_key": "D", "hint": "The Assertion is correct: from f = qB/(2πm), the frequency clearly does not contain velocity v, confirming it is independent of speed.", "misconception": "Thinking cyclotron frequency depends on speed"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Increasing the number of turns in a moving coil galvanometer always increases both its current sensitivity and voltage sensitivity. Reason (R): Current sensitivity is NAB/k and voltage sensitivity is NAB/(kG), and increasing N increases the resistance G of the coil.", "explanation": "The Assertion is incorrect. While increasing N does increase current sensitivity (Is = NAB/k), it also increases the coil resistance G (since G is proportional to N for a given wire). Voltage sensitivity Vs = NAB/(kG) = Is/G. As N increases, both NAB/k and G increase, and the net effect on Vs depends on the relative rates. In fact, since G is proportional to N (longer wire), Vs = NAB/(kG) may remain roughly constant or even decrease. So increasing N does NOT always increase voltage sensitivity. The Reason is correct: it correctly states both formulas and that increasing N increases G.", "correct_answer": "D", "concept_tags": ["current-sensitivity", "voltage-sensitivity", "number-of-turns", "galvanometer-design"], "payload": {"question_id": "cuet-phy-magmov-devices-14", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The Assertion claims increasing N always increases both sensitivities. But since G also increases with N, voltage sensitivity Vs = NAB/(kG) may not increase. The Assertion is therefore incorrect.", "misconception": "Ignoring the effect of increased resistance when adding more turns"}, {"option_key": "B", "hint": "Since the Assertion is incorrect (voltage sensitivity does not necessarily increase with N), options involving ''A is correct'' cannot be right.", "misconception": "Not analyzing the voltage sensitivity formula carefully"}, {"option_key": "C", "hint": "The Reason correctly states the formulas and the fact that G increases with N. This is physically accurate since more turns mean longer wire and greater resistance.", "misconception": "Thinking the Reason is wrong about resistance increasing with turns"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Cyclotron frequency\n(Q) Shunt resistance for ammeter\n(R) Series resistance for voltmeter\n(S) Current sensitivity of galvanometer\n\nColumn II:\n(1) NAB/k\n(2) V/Ig - G\n(3) qB/(2πm)\n(4) Ig·G/(I - Ig)", "explanation": "P-3: Cyclotron frequency f = qB/(2πm). Q-4: Shunt resistance S = Ig·G/(I - Ig) for converting galvanometer to ammeter. R-2: Series resistance R = V/Ig - G for converting galvanometer to voltmeter. S-1: Current sensitivity = NAB/k, which is the deflection per unit current in a galvanometer.", "correct_answer": "B", "concept_tags": ["cyclotron-frequency", "ammeter-conversion", "voltmeter-conversion", "current-sensitivity", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-devices-15", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "understand", "options": [{"key": "A", "text": "P-3, Q-2, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-3, Q-4, R-2, S-1", "is_correct": true}, {"key": "C", "text": "P-4, Q-3, R-1, S-2", "is_correct": false}, {"key": "D", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This swaps Q and R. The shunt resistance formula contains Ig·G/(I - Ig) which is (4), while the series resistance formula is V/Ig - G which is (2). So Q matches 4, not 2.", "misconception": "Swapping the ammeter and voltmeter conversion formulas"}, {"option_key": "C", "hint": "P-4 would match cyclotron frequency to the shunt formula, which is dimensionally inconsistent. Cyclotron frequency has units of Hz = 1/s, while Ig·G/(I-Ig) has units of Ω.", "misconception": "Not checking dimensional consistency of the formulas"}, {"option_key": "D", "hint": "P-1 matches cyclotron frequency with NAB/k, which is the current sensitivity formula. Cyclotron frequency f = qB/(2πm) matches with (3).", "misconception": "Confusing cyclotron frequency with galvanometer sensitivity"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field inside a long solenoid\n(Q) Magnetic field of a toroid (inside)\n(R) Cyclotron maximum KE\n(S) Deflecting torque in a galvanometer\n\nColumn II:\n(1) NIAB\n(2) μ₀nI (n = turns per unit length)\n(3) q²B²R²/(2m)\n(4) μ₀NI/(2πr)", "explanation": "P-2: The magnetic field inside a long solenoid is B = μ₀nI, where n is the number of turns per unit length. Q-4: Inside a toroid, B = μ₀NI/(2πr), where N is total turns and r is the radius of the toroidal path. R-3: Maximum kinetic energy from a cyclotron is q²B²R²/(2m). S-1: The deflecting torque on the coil in a galvanometer is τ = NIAB.", "correct_answer": "A", "concept_tags": ["solenoid", "toroid", "cyclotron-energy", "galvanometer-torque", "match-the-following"], "payload": {"question_id": "cuet-phy-magmov-devices-16", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": false}, {"key": "D", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This swaps P and Q. The solenoid field B = μ₀nI uses turns per unit length (n), while the toroid field B = μ₀NI/(2πr) uses total turns N and has r in the denominator.", "misconception": "Confusing the solenoid and toroid magnetic field formulas"}, {"option_key": "C", "hint": "R-1 would match cyclotron KE with NIAB (torque). The cyclotron KE expression q²B²R²/(2m) is (3), and NIAB is the galvanometer torque (1).", "misconception": "Swapping the cyclotron energy and galvanometer torque expressions"}, {"option_key": "D", "hint": "Q-1 would match toroid field with NIAB, which is the torque expression for a galvanometer. The toroid field is μ₀NI/(2πr), which is (4).", "misconception": "Not distinguishing between the torque formula and the toroid field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside a solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This statement is TRUE. Inside a long solenoid (ideal case), the magnetic field is uniform in both magnitude and direction. The field lines run parallel to the axis of the solenoid. This can be derived using Ampere''s law, which gives B = μ₀nI inside the solenoid (where n = N/L is the number of turns per unit length). Outside the solenoid, the field is approximately zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-magnetic-field", "field-direction"], "payload": {"question_id": "cuet-phy-magmov-devices-17", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The field inside an ideal long solenoid is indeed uniform and axial. This is a standard result from Ampere''s law applied to a rectangular Amperian loop.", "misconception": "Confusing solenoid field with that of a bar magnet, where the field is non-uniform"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "A cyclotron can be used to accelerate electrons to high energies efficiently.", "explanation": "This statement is FALSE. A cyclotron cannot efficiently accelerate electrons because electrons have very small mass (9.1 x 10^-31 kg). Due to their low mass, electrons quickly reach relativistic speeds, at which point their mass increases significantly (relativistic mass increase). This causes the cyclotron frequency f = qB/(2πm) to decrease, and the particles go out of synchronization with the fixed-frequency oscillating electric field. This is a well-known limitation of the cyclotron.", "correct_answer": "B", "concept_tags": ["cyclotron", "electrons", "relativistic-effects", "limitation"], "payload": {"question_id": "cuet-phy-magmov-devices-18", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Electrons have very small rest mass, so they reach relativistic speeds at relatively low energies. At relativistic speeds, the effective mass increases, changing the cyclotron frequency and causing loss of synchronization.", "misconception": "Thinking the cyclotron works for all charged particles without considering relativistic effects"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "In a moving coil galvanometer, a radial magnetic field is produced by using concave-shaped pole pieces and a _____ placed inside the coil.", "explanation": "A soft iron core is placed inside the coil of a moving coil galvanometer. The soft iron core, along with the concave-shaped (cylindrical) pole pieces of the permanent magnet, creates a radial magnetic field. In a radial field, the plane of the coil is always parallel to the magnetic field direction, so the torque τ = NIAB sin(90°) = NIAB for all angular positions. This ensures a linear relationship between the current and the deflection angle (θ ∝ I).", "correct_answer": "C", "concept_tags": ["moving-coil-galvanometer", "radial-field", "soft-iron-core", "construction"], "payload": {"question_id": "cuet-phy-magmov-devices-19", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "remember", "options": [{"key": "A", "text": "Hard iron core", "is_correct": false}, {"key": "B", "text": "Copper cylinder", "is_correct": false}, {"key": "C", "text": "Soft iron core", "is_correct": true}, {"key": "D", "text": "Permanent magnet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Hard iron retains magnetism (used for permanent magnets) and is not suitable for the core. Soft iron is used because it has high permeability, low retentivity, and strengthens the radial field without permanent magnetization.", "misconception": "Confusing soft iron (high permeability, low retentivity) with hard iron (permanent magnets)"}, {"option_key": "B", "hint": "A copper cylinder is not used as the core. Copper is non-magnetic and would not help in creating a radial magnetic field. Soft iron''s high magnetic permeability is essential for concentrating field lines.", "misconception": "Confusing copper damping mechanism with the iron core"}, {"option_key": "D", "hint": "The permanent magnet provides the external magnetic field and is located outside the coil (as pole pieces). The core inside the coil is soft iron, which helps make this external field radial.", "misconception": "Confusing the location and role of the permanent magnet with the core"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-devices", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A medical research lab uses a cyclotron to produce radioactive isotopes for PET (Positron Emission Tomography) scans. The cyclotron accelerates protons using a magnetic field of 2.0 T. The protons are extracted when they reach a radius of 0.4 m from the centre. If the cyclotron''s oscillating electric field operates at a fixed frequency, what is the frequency of the oscillating electric field, and what is the kinetic energy of the extracted protons? (Given: mass of proton = 1.67 x 10^-27 kg, charge = 1.6 x 10^-19 C)", "explanation": "The cyclotron frequency f = qB/(2πm) = (1.6 x 10^-19 x 2.0)/(2π x 1.67 x 10^-27) = 3.2 x 10^-19 / (1.049 x 10^-26) = 3.05 x 10^7 Hz ≈ 30.5 MHz. The maximum kinetic energy KE = q²B²R²/(2m) = (1.6 x 10^-19)² x (2.0)² x (0.4)² / (2 x 1.67 x 10^-27) = (2.56 x 10^-38 x 4 x 0.16) / (3.34 x 10^-27) = 1.638 x 10^-38 / 3.34 x 10^-27 = 4.9 x 10^-12 J. Converting: 4.9 x 10^-12 / 1.6 x 10^-13 ≈ 30.6 MeV. So the frequency is approximately 30.5 MHz and KE is approximately 30.6 MeV.", "correct_answer": "B", "concept_tags": ["cyclotron", "frequency", "kinetic-energy", "PET-scan", "medical-application", "numerical"], "payload": {"question_id": "cuet-phy-magmov-devices-20", "subtopic": "Galvanometer, Ammeter, and Voltmeter", "topic_name": "Galvanometer, Ammeter, and Voltmeter", "bloom_level": "apply", "options": [{"key": "A", "text": "Frequency ≈ 15.2 MHz, KE ≈ 15 MeV", "is_correct": false}, {"key": "B", "text": "Frequency ≈ 30.5 MHz, KE ≈ 30.6 MeV", "is_correct": true}, {"key": "C", "text": "Frequency ≈ 30.5 MHz, KE ≈ 61 MeV", "is_correct": false}, {"key": "D", "text": "Frequency ≈ 61 MHz, KE ≈ 30.6 MeV", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "15.2 MHz is half the correct frequency. Check your calculation: f = qB/(2πm). With B = 2.0 T, the numerator is qB = 3.2 x 10^-19, not 1.6 x 10^-19. Ensure you use B = 2.0 T, not 1.0 T.", "misconception": "Using B = 1.0 T instead of 2.0 T in the frequency formula"}, {"option_key": "C", "hint": "The frequency is correct at 30.5 MHz, but 61 MeV is double the actual KE. Verify the factor of 2 in the denominator: KE = q²B²R²/(2m), not q²B²R²/m.", "misconception": "Forgetting the factor of 2 in the kinetic energy denominator"}, {"option_key": "D", "hint": "61 MHz is double the correct frequency. The formula is f = qB/(2πm), and 2π ≈ 6.28, not π ≈ 3.14. Using π instead of 2π would give the wrong answer.", "misconception": "Using π instead of 2π in the cyclotron frequency formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A charged particle moving with velocity v enters a uniform magnetic field B perpendicular to its velocity. The magnetic force on the particle is:", "explanation": "The magnetic force on a moving charged particle is given by F = qv × B. When the velocity is perpendicular to the magnetic field (θ = 90°), sin 90° = 1, so F = qvB. This is the maximum force the magnetic field can exert on the charge.", "correct_answer": "A", "concept_tags": ["lorentz-force", "magnetic-force", "moving-charge"], "payload": {"question_id": "cuet-phy-magmov-force-01", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "qvB", "is_correct": true}, {"key": "B", "text": "qvB/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "qv/B", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The factor of 1/2 does not appear in the Lorentz force formula. F = qvB sinθ has no such coefficient.", "misconception": "Confusing with kinetic energy formula which has a 1/2 factor"}, {"option_key": "C", "hint": "Force is zero only when the charge moves parallel to B (θ = 0°). Here the motion is perpendicular to B, so sinθ = 1.", "misconception": "Confusing perpendicular and parallel motion relative to B"}, {"option_key": "D", "hint": "Dimensionally, qv/B gives C·m/(s·T) which does not have units of force. The correct formula has B in the numerator.", "misconception": "Incorrectly placing B in the denominator"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A proton moves parallel to a uniform magnetic field. The force acting on the proton is:", "explanation": "The magnetic force on a charged particle is F = qvB sinθ. When the particle moves parallel to B, the angle θ = 0°, and sin 0° = 0. Therefore, F = 0. A magnetic field exerts no force on a charge moving along the field direction.", "correct_answer": "B", "concept_tags": ["magnetic-force", "parallel-motion", "zero-force"], "payload": {"question_id": "cuet-phy-magmov-force-02", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "qvB", "is_correct": false}, {"key": "B", "text": "Zero", "is_correct": true}, {"key": "C", "text": "qvB/2", "is_correct": false}, {"key": "D", "text": "qB/v", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "F = qvB applies only when v is perpendicular to B (θ = 90°). Here the motion is parallel, so sinθ = 0.", "misconception": "Ignoring the sinθ dependence in the Lorentz force"}, {"option_key": "C", "hint": "There is no 1/2 factor in the force formula, and regardless the force is zero when velocity is parallel to B.", "misconception": null}, {"option_key": "D", "hint": "This expression is dimensionally incorrect for force and does not correspond to any known formula.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The work done by a magnetic force on a charged particle moving in a magnetic field is:", "explanation": "The magnetic force F = qv × B is always perpendicular to the velocity of the charged particle. Since work done W = F · ds = F · v dt, and F is perpendicular to v, the dot product F · v = 0. Hence, the magnetic force does no work on a moving charge. It can only change the direction of velocity, not its magnitude.", "correct_answer": "C", "concept_tags": ["work-done", "magnetic-force", "perpendicular-force"], "payload": {"question_id": "cuet-phy-magmov-force-03", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "understand", "options": [{"key": "A", "text": "Positive", "is_correct": false}, {"key": "B", "text": "Negative", "is_correct": false}, {"key": "C", "text": "Always zero", "is_correct": true}, {"key": "D", "text": "Depends on the magnitude of charge", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Magnetic force is always perpendicular to velocity. A perpendicular force cannot increase the kinetic energy or do positive work.", "misconception": "Assuming any force that acts on a moving particle does work"}, {"option_key": "B", "hint": "Negative work would slow down the particle. But the speed of a charged particle in a pure magnetic field remains constant.", "misconception": "Confusing magnetic force with a drag or resistive force"}, {"option_key": "D", "hint": "Regardless of the magnitude of charge, the magnetic force is always perpendicular to displacement, so work is always zero.", "misconception": "Thinking work depends on charge magnitude alone"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-lorentz-force", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two long parallel conductors carry currents in the same direction. The force between them is:", "explanation": "When two parallel conductors carry currents in the same direction, the magnetic field produced by one conductor at the location of the other results in an attractive force between them. This can be verified using the right-hand rule: the field from one wire at the other wire''s location creates a force directed toward the first wire. Currents in opposite directions repel each other.", "correct_answer": "A", "concept_tags": ["parallel-conductors", "force-between-conductors", "attractive-force"], "payload": {"question_id": "cuet-phy-magmov-force-04", "subtopic": "Lorentz Force and Motion in Fields", "topic_name": "Lorentz Force and Motion in Fields", "bloom_level": "remember", "options": [{"key": "A", "text": "Attractive", "is_correct": true}, {"key": "B", "text": "Repulsive", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "Attractive or repulsive depending on the magnitude of currents", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Repulsive force occurs between parallel conductors carrying currents in opposite directions. Same-direction currents always attract.", "misconception": "Confusing same-direction and opposite-direction current rules"}, {"option_key": "C", "hint": "Two current-carrying conductors always exert a force on each other. The force is zero only when one of the currents is zero.", "misconception": "Thinking parallel conductors do not interact magnetically"}, {"option_key": "D", "hint": "The nature of the force (attractive/repulsive) depends only on the relative direction of currents, not on their magnitudes.", "misconception": "Confusing the nature of force with its magnitude"}]}}]'::jsonb, 'deploy-2026-03-05-b12');

COMMIT;
